INSERT INTO `activos` (`id`, `rfk`, `titulo`, `usuario_creado_por`, `fecha_creacion`, `usuario_modificado_por`, `fecha_ultima_modificacion`, `descripcion`, `propietario`, `tipo`, `fabricante`, `modelo`, `serie`, `ubicacion`, `fallas_activas`) VALUES ('388', 'AK7902436', 'Cargador de Notebook DELL Latitude 5400', NULL, '2026-02-03 16:26:10', NULL, '2026-02-03 16:26:10', 'Cargador de Notebook DELL Latitude 5400: #AK7902274  Codigo QR: CN-004VKN-CH200-96001N4-A01  DP/N: 004VKN  Etiqueta de activo fijo color: AMARILLA  ///////////// EXTRAVIADO /////////////    Este cargador estaba siendo trabajado en ticket: #USX.T612604 pero se extravió.    Detalles del incidente:  Originalmente el notebook Dell Latitude #AK7902274 (etiqueta de activo fijo color amarilla) vino con el cargador #AK7902436 (etiqueta de activo fijo color amarilla) y hasta el formateo del mismo ese cargador estuvo en la oficina de soporte.   Sin embargo de un día para el otro este cargador #AK7902436 desapareció y fue súbitamente reemplazado por el cargador: #AK7902464 que apareció de la nada en la oficina.  Ambos cargadores son prácticamente iguales y de mismo voltaje y aparentemente para el mismo modelo de Notebook.   Se cree que durante el restablecimiento/formateo de equipo o después del mismo existió una confusión donde los cargadores se confundieron, o alguien que ingreso a la oficina de soporte con algún Dell se llevo el cargador  #AK7902436 por error y dejó el #AK7902464  Al momento se esta intentando determinar que ocurrió. El echo sin embargo es muy extraño.', 'GOREOHIGGINS', 'CARGADOR', 'DELL', '', 'CN-004VKN-CH200-96001N4-A01', 'GORE', '0');
