INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('8', 'DCD.T0000007', 'Activacion Inicio Automatico en ESXi para maquinas virtuales', 'técnico', 'Al ingresar en la sesión de cada vmware,  1. seleccione una maquina virtual  2. seleccione en el menu acciones, se desplegara un submenu  3. seleccione inicio automatico  4. seleccione habilitar', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('9', 'DCD.T0000008', 'ActivationCodes_31EA-230202-142337-460-950 (Kaspersky)', 'técnico', 'ActivationCodes_31EA-230202-142337-460-950.txt  Caso: #USX.T638742', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('10', 'DCD.T0000009', 'Actualizar ruta de actualizacion PYR', 'técnico', 'Para cambiar la ruta de actualizcion de sistema PYR se debe realizar lo siguiente:    - Abrir sistema PYR  - Inciar sesion  - Click en Sistema -> Configurar Parámetros de sistema  - Buscar el codigo identificador \"RUTAEXE\" en el debe haber una ruta, ej: 10.6.6.60\\...  - Insertar nueva de actualizacion  - Guardar, cerrar y reinicar sistema PYR     Nota: Segun proveedor al cambiar la ruta en un equipo, se cambiara en el resto de equipos en donde este instalado el sistema PYR.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('11', 'DCD.T0000010', 'Agregar el calendario de Exchange de otra persona en mi Outlook', 'técnico', 'Para agregar un calendario compartido de otra persona en tu Outlook, debes seguir los pasos descritos por Microsoft, esta no es una tarea que puedas realizarse centralizadamente desde una consola administrativa, debes hacerlo en el computador del usuario, por lo que se recomienda que se coordine una sesión remota o presencial para tal labor.    <a href=\'https://support.microsoft.com/es-es/office/abrir-el-calendario-de-exchange-de-otra-persona-2257f515-408f-48ea-9363-11d0d5848c77\' target=\'_blank\'>Abrir el calendario de Exchange de otra persona</a>  ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('12', 'DCD.T0000011', 'ANEXOS 2020', 'técnico', 'Listado de anexos GORE  #USX.T610517', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('13', 'DCD.T0000012', 'Apagado Global de Sala Computación Goreohiggins', 'técnico', 'El Apagado comprende:  Sala de computación con sus 3 racks  Sala de computación DAF con 1 rack    El alcance del apagado es apagar maquina por sistema o boton físico, despues desconectar el cable que alimenta al equipo.    1. Se apagan los servidores wmware (remoto)  2. Se apagan los NAS (remoto)  3. Se desconectan los switchs  4. Se desconecta la Central telefónica  5. Se desconectan NVR  6. Se apaga UPS (#AK7902905, #AK7902815 y #AK7902816)      PD: Detras del rack 3 #AK7902130 ubicado en oficina TI hay 3 enchufes los cuales hay que desconectar una vez apagadas las UPS y con eso se finalizaria el procedimiento de apagado', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('14', 'DCD.T0000013', 'Archivar correos en PST de Outlook', 'técnico', 'Archivar correos de Microsoft 365 Exchange  OnLine en un PST. Use este procedimiento para respaldar o para liberar espacio en un buzón de correo.    Pasos  YYYY= el año de los correos recibidos y enviados    1) Agrega archivo PST (#USX.PR1258 Como agregar archivos \"pst\" al cliente de correo Outlook)  Nombre: YYYY  Nombre Archivo: gisela.aguirre.YYYY.pst  Ubicación: OneDrive\\Outlook    2) Mueve correos anteriores al 1 de enero del YYYY desde y hacia:  Bandeja de Entrada - > YYYY/Bandeja de Entrada  Elementos Enviados -> YYYY/Elementos Enviados  Nota1: Si existen otras carpetas, debe aplicar el mismo criterio.  Nota2: Mover los mensajes produce que le buzón se desocupe, por lo tanto no es necesario que realicemos una acción adicional.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('15', 'DCD.T0000014', 'Arquitectura VMWare (Servidores Físicos) GOREOHIGGINS', 'técnico', 'GOREOHIGGINS Arquitectura VMWare  (Servidores Físicos)  #USX.T639208', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('16', 'DCD.T0000015', 'Asegurar que la sesión de TeamViewer se encuentre activa en un equipo goreohiggins', 'técnico', 'Se debe verificar que el servicio de conexión esté UP y que la configuración con la cuenta de soporte esté operativa, esto se verifica en el cliente de teamviewer-->opciones-->general-->asignación de cuenta (ver imagen en sección propiedades de este procedimiento)    Para conectarse sin que le solicite las credenciales en forma remota revisar el procedimiento #USX.PR1272', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('17', 'DCD.T0000016', 'Asesoría en adquisición de equipos', 'técnico', '', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('18', 'DCD.T0000017', 'Backup switch GOREOHIGGINS', 'técnico', 'En propiedades del procedimiento se encuentra un manual en formato PDF para realizar esta tarea.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('19', 'DCD.T0000018', 'Bloquear celdas en Excel', 'técnico', '1. Hacemos click con el mouse en la esquina izquierda superior (esquina donde se encuentra los numeros y las letras)seleccionando toda la hoja.  2. Click boton derecho del mouse.  3. Seleccionamos formato de celda.  4. Seleccionamos la pestaña proteger.  5. Desactivamos la opción desbloquear y aceptamos. Volvemos a la hoja.  6. Luego en la hoja, seleccionamos las celdas que queremos proteger,   7. Click boton derecho del mouse.  8. Seleccionamos la pestaña proteger.  9. Activamos la opción bloqueada. y aceptar.  10. Para proteger la hoja, vamos a la pestaña revisar.  11. Seleccionamos proteger hoja, nos pide asignar contraseña.  12. Asigne contraseña, luego aceptar    fuente:https://miracomosehace.com/bloquear-proteger-celdas-excel/', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('20', 'DCD.T0000019', 'Calendario TEAMS no coordina en todas las plataformas en las que el usuario lo tiene abierto. (WINDOWS y ANDROID por ejemplo).', 'técnico', 'Para poder resolver el inconveniente donde el usuario no puede visualizar el otros dispositivos el calendario con la misma información que tiene en su TEAMS de Windows se deben seguir los siguientes pasos:  1 - Ingresar al Centro de administración de Microsoft 365:  https://admin.microsoft.com/Adminportal/Home?#/users  2 - En la parte izquierda del sitio buscar la opción \"USUARIOS ACTIVOS\" y en el box de búsqueda que se encuentra a la izquierda tipear el nombre del usuario con problemas.  3 - Una vez que se ubica al usuario con problemas abrir el perfil del usuario (haciendo click sobre el nombre del usuario) e ir a la pestaña \"Licencias y aplicaciones\"  4 - Dentro de la pestaña \"Licencias y aplicaciones\" se debe destildar el box que tiene por nombre \"Microsoft Teams Exploratory\"  5 - Una vez que paso 4 fue realizado solo resta hacer que el usuario se deslogee de su aplicativo TEAMS en todas las plataformas en las que lo utiliza.   En este punto se debe esperar aprox. unas 4 horas para estar seguros de que los cambios realizados en sistema se verán reflejados en la plataforma Office.   6 - El paso final es volver a ingresar al aplicativo TEAMS y el calendario debería ya estar coordinado en todos los dispositivos respectivamente.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('21', 'DCD.T0000020', 'Cambiar dirección onmicrosoft de un usuario sincronizado', 'técnico', 'Ver este articulo:  http://o365support.weebly.com/blog/cambiar-direccion-onmicrosoft-de-un-usuario-sincronizado-en-un-ad-local', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('22', 'DCD.T0000021', 'Cambio de contraseña de dominio GOREOHIGGINS', 'técnico', '1) Busca en Usx al usuario  2) Asegúrate que exista un teléfono en sus atributos. El teléfono debe estar escrito en la forma internacional +569xxxxxxxx  3) Haz clic en el menú acciones y luego en \"Preparar SMS para cambio de clave\"  4) Copia la contraseña que te entrega la página y haz el cambio manual en el dominio, no cierres esta página.  5) Una vez hecho el cambio de contraseña, vuelve a la página de Usx y haz clic en el icono ANDROID o IOS según el teléfono que vayas a usar.  6) Toma el teléfono que usaras para enviar el SMS, y escanea el código QR.  7) En el teléfono se abrirá la aplicación de SMS y haz clic en enviar.  ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('23', 'DCD.T0000022', 'CAMBIO DE HORA DE VERANO EN CHILE [PASO A PASO] 2022', 'técnico', 'Estimado Oscar,     Nos ponemos en contacto porque teniendo en cuenta el próximo cambio de actualización de la zona horaria, es de suma importancia que como cliente conozca el paso a paso para realizar la modificación de forma manual en los equipos dentro de su organización.     Dado que la actualización estaba prevista dentro del ciclo de actualizaciones de Windows Update para el día 4 de septiembre, ese día cambiará automáticamente la hora de todos los equipos con sistema operativo Windows y que tienen activadas las actualizaciones automáticas. Por eso recomendamos a los usuarios que deshabiliten temporalmente los ajustes automáticos de cambio de hora (DST) en Windows para reflejar la hora local correcta entre el 4 de septiembre y el 11 de septiembre de 2022.     Para evitar desajustes en el reloj, recomendamos a los usuarios seguir los siguientes pasos:     Paso 1 - Antes de la medianoche del 3 de septiembre:  Seleccione el logotipo de Windows, luego haga clic en Configuración, y después escriba Fecha y hora en el buscador.  En la página Configuración de fecha y hora, desactive la opción “Ajustar para el horario de verano automáticamente” dejándola en OFF.     Paso 2 – A las 00:00 hrs. del 11 de septiembre (sábado por la noche):  Seleccione el logotipo de Windows, luego haga clic en Configuración, y después escriba Fecha y hora.  En la página Configuración de fecha y hora, vuelva a activar la opción “Ajustar para el horario de verano automáticamente” dejándolo en ON.     Para aquellos clientes con soporte corporativo activo, ante cualquier duda equipo global de atención al cliente está preparado para atenderlo.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('24', 'DCD.T0000023', 'Certificate 31EA-230202-142337-460-950 (Kaspersky)', 'técnico', 'Certificate 31EA-230202-142337-460-950.pdf  CAso:#USX.T638742', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('25', 'DCD.T0000024', 'Como  cambiar la cuenta de correo principal de una cuenta Exchange365', 'técnico', 'Vaya a Exchange Admin Center  En el panel izquierdo seleccione Mailboxes  En el panel derecho, seleccione la cuenta para la que desea hacer el cambio, para ver sus propiedades  En el panel de las propiedades haga clic en \"Manage email address types\"  En la lista de direcciones, localice la cuenta del tipo smtp que desee dejar como principal y haga clic en \"Edit\"  En el panel de edición, activa la casilla \"Make this the reply address\" y luego haga clic en el boton \"Save\"    recuerde esperar 30 minutos para que los cambios tengan efecto.    Para probar en las sugerencias, debe desconectarse de outlook y volver a conectarse para que los cambios surtan efecto.  ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('26', 'DCD.T0000025', 'Como acceder a Avaya IP Office Manager en GOREOHIGGINS', 'técnico', 'Conectate a una máquina que tenga instalado Avaya IP Office manager (PC-Soporte)  ejecuta la aplicación Manager  Menu-> Archivo -> Abrir Configuracion  En el recuadro Dirección Unidad de Difusion ingresa la IP 10.6.20.2 y haz clic en Actualizar  En el recuadro superior marca la opción llamada GoreOhiggins y haz clic en Aceptar  En el inicio de sesión, nombre de usuario soporte.gore y contraseña <psw:ipo.goreohiggins.cl>  ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('27', 'DCD.T0000026', 'Como activar el desvio de llamadas entrantes a telefono celular', 'técnico', 'Tecla Función  Reenviar  Reenviar Incondicional  Rem.Incondic -> Activar  Tipo de Llamada -> Todas las llamadas  Destino-> 9<telefono sin +56>  Guardar', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('28', 'DCD.T0000027', 'Como Activar Modulo Resoluciones, y modulo aviso de sistema, avisos web en sistema PYR de escritorio RRHH', 'técnico', '', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('29', 'DCD.T0000028', 'Como actualizar base PYRPRUEBAS y PYRPROPRUEBAS en GORE-DAF-SRV01 o SRV-DBINGSOFT\\PYR', 'técnico', '1) Conéctate via RDP a GORE-DAF-SRV01  2) Abre SQL Management Studio   3) Conéctate a la instancia GORE-DAF-SRV01\\DAFGORE usando la cuenta PYR  4) Abre el archivo USX.PR1276.Update.V2.sql (CTRL+O) localizado en C:\\Backup\\USX.PR1276  5) Ejecuta el script contenido en el archivo.  6) Listo, ya puedes cerrar.    Para pyrPro debes realizar lo mismo, pero utilizando el archivo: USX.PR1276.Update.pyrProPrueba.v2.sql localizado en:  D:\\Backup\\MSSQL\\GORE-DAF-001.DAFGORE\\ONE USX.PR1276', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
