INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('31', 'DCD.T0000030', 'Como agregar archivos \"pst\" al cliente de correo Outlook', 'técnico', '1.- Abrir Cliente Outlook  2.- Seleccionar Configuración de la Cuenta  3.- Ir a la pestaña \"Archivos de Datos\"   4.- Seleccionar Agregar  5.- Buscar la ruta en la cual está el archivo pst que se debe agregar', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
