INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('33', 'DCD.T0000032', 'Como Almacenar Backup Plataforma UNMS', 'técnico', 'La plataforma UNMS almacena los respaldos, estos se deben bajar para almacenarlos en la tarea generada en el item documento de la misma.  se crea tarea recurrente #USX.RT1839', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('34', 'DCD.T0000033', 'Como asignar nombre de sistema operativo a instalar en NOTEBOOK o DESKTOP', 'técnico', 'Este procedimiento necesita el código de ASSET al cual le instalarán el sistema operativo.    Ingrese un registro en el catalogo de sistemas usando un nombre temporal  Una vez creado use el identificador de sistema o el RFK y ponga el nombre   NB-S#### para los ASSETS del tipo NOTEBOOK  PC-S#### para los ASSETS del tipo DESKTOP    En el campo descripción agregar la referencia del ASSET donde se está instalando el sistema operativo  En el campo SYSTEM TYPE, debe colocar \"Operating System.    ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('35', 'DCD.T0000034', 'Como asignar permiso para que una cuenta pueda enviar un mensaje a un grupo Microsoft 365', 'técnico', 'Vaya al centro de Administración Exchange (https://go.microsoft.com/fwlink/p/?linkid=2059104)  Destinatarios -> Grupos -> Busque el Grupo -> Selecciónelo -> Haga clic en el botón Editar  Seleccione Administración de Entregas  Haga clic en el botón + para agregar una cuenta.  Agregue la cuenta  Finalmente, clic en Guardar', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('36', 'DCD.T0000035', 'Cómo asignar permisos a usuarios en carpetas compartidas', 'técnico', '', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
