INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('38', 'DCD.T0000037', 'Cómo bajar archivo \"message\" con registros de conexión Openvpn', 'técnico', '1. Se debe conectar a Router Edge #AK7902135 via WinScp (solicitar credenciales a #claudio)  2. Ir a la ruta \\var\\log  3. Buscar archivo \"message\"  4. Bajar a ubicación preferida.  ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('39', 'DCD.T0000038', 'Como Bloquear dominio o correo en Office 365', 'técnico', 'referencia https://learn.microsoft.com/es-es/microsoft-365/security/office-365-security/tenant-allow-block-list-email-spoof-configure?view=o365-worldwide  ir a: https://security.microsoft.com  1. Reglas y directivas  2. Directivas de amenazas  3. Lista de bloqueados y permitidos de espacio empresarial  4. Crear regla', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('40', 'DCD.T0000039', 'Como cambiar configuración SMTP en módulo web ingsoft', 'técnico', '#USX.EC22124  #USX.T617104', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('41', 'DCD.T0000040', 'Como cambiar datos de organización Microsoft 365 One Drive', 'técnico', 'Para cambiar los datos de la organización en Microsoft 365, estos cambios son reflejados en las paginas de inicio de sesión y facturas emitidas. Además de la carpeta One Drive.  Ver documento adjunto.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('42', 'DCD.T0000041', 'Como cambiar la contraseña de una cuenta de dominio con PowerShell', 'técnico', 'Set-ADAccountPassword -Identity \'elusuariodeldominio\' -Reset -NewPassword (ConvertTo-SecureString -AsPlainText \"lacontraseña\" -Force) -Server \"servidordedominio\"', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('43', 'DCD.T0000042', 'Como cambiar la hora del reloj control de goreohiggins', 'técnico', 'Para iniciar sesión sin huella en cada dispositivo, puede consultar el procedimiento #USX.PR1365 Como iniciar sesion superadmin en reloj control  Aplica a #AK7902093 #AK7902107', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('44', 'DCD.T0000043', 'Como capturar llamadas de otros anexos', 'técnico', 'se debe digitar el siguiente comando:    *32*N# Capturar llamadas extensión  *30 Capturar cualquier llamada    N = número de anexo.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('45', 'DCD.T0000044', 'Cómo comprobar la integridad de Windows', 'técnico', 'Cuando tengas problemas con windows y pienses que hay algo que no funciona bien y no sabes que podría estar causando ese problema, es recomendable ejecutar una comprobación de windows y del disco, para ello, ejecute las siguientes instrucciones en CMD o Linea de Comandos de Windows.    1) abre una ventana CMD como administrador    2) en la ventana escribe y ejecuta cada una de estas instrucciones:  <pre>sfc /scannow  DISM /Online /Cleanup-Image /CheckHealth  DISM /Online /Cleanup-Image /ScanHealth  DISM /Online /Cleanup-Image /RestoreHealth  chkdsk C: /F /R</pre>', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('46', 'DCD.T0000045', 'Como configurar envíos de correo como otro remitente.', 'técnico', 'Enviar correo electrónico desde una dirección de correo electrónico diferente  En la ventana de redacción, seleccione Más acciones > Mostrar De para ver la línea De.    Seleccione De y elija la dirección de correo electrónico que quiera usar.        https://support.microsoft.com/es-es/office/enviar-correo-electr%C3%B3nico-desde-una-direcci%C3%B3n-diferente-en-outlook-com-ccba89cb-141c-4a36-8c56-6d16a8556d2e', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('47', 'DCD.T0000046', 'Como configurar grupos de saltos en AVAYA', 'técnico', 'Para configurar grupos de saltos, debe escalarlo con el proveedor, ellos hacen la configuración.    #USX.PR1228 Solicitar Soporte de Telefonía a Movistar (Avaya)', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('48', 'DCD.T0000047', 'Cómo configurar la OPEN VPN Gui', 'técnico', 'Los siguientes archivos se deben copiar en la instalacion de la vpn, los cuales están configurados para que funcione:  gore.ovpn  gore.pem  gore.key  cacert.pem', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('49', 'DCD.T0000048', 'como configurar mensaje de vacaciones en Outlook', 'técnico', 'revisar documento adjunto en item propiedades', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('50', 'DCD.T0000049', 'Como configurar modulo web (INGSOFT) para el envío de correos', 'técnico', 'Para permitir que ModuloWeb pueda enviar correos usted debe abrir el archivo web.config ubicado en la ruta de red \\\\10.6.1.41\\rrhh  a partir de la linea 751 usted deberá proporcionar los siguientes datos.  ServidorCorreo: smtp.office365.com  UsuarioCorreo: rrhh@goreohiggins.cl  PasswordCorreo: Gob.2021.gore  SmtpUseSSL: true  SmtpSSLPort: 587  SmtpUsaUsr: SI    #USX.S1519 http://moduloweb.goreohiggins.cl', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('51', 'DCD.T0000050', 'Cómo configurar opción UNMS en Switch EdgeSwitch', 'técnico', '1. Ingresar al switch por web con la IP  2. Seleccionar System Settings  3. Copiar key en UNMS Key (obtenida de la administración UNMS, ver #USX.PR1225)  4. Seleccionar APPLY', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('52', 'DCD.T0000051', 'Cómo configurar puertas en modo trunk en switch edge', 'técnico', '1. Ingresar al switch  2. ir al menú Switching > VLAN > Port Configuration  3. seleccionar puerta y editar  4. en opcion Acceptable frame type, seleccionar Admit all   5. en la opción Ingress filtering seleccione disable    6. ir al menu Switching > VLAN > Port Configuration  7. seleccione puerta y editar  8. en la opción participation seleccionar include  9. en la opción tagging seleccione untagged', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('53', 'DCD.T0000052', 'Como configurar PYR (INGSOFT) para que envíe liquidaciones por correo', 'técnico', 'Siga las instrucciones del documento anexo.  Fuente: Este instructivo está basado en la <a href=\'https://ingsoft.freshdesk.com/support/discussions/topics/6000062459\' target=\'_blank\'>documentación</a> del fabricante', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('54', 'DCD.T0000053', 'Como configurar sitio de confianza para abrir archivos de la red sin advertencia de seguridad', 'técnico', 'A menudo suele recibir un mensaje de advertencia #USX.EC22123 Mensaje de Windows No podemos verificar quién creó este archivo, cuando intenta abrir un archivo de la red que usted conoce, para evitar este mensaje para esos archivos, usted puede agregar un sitio de confianza, para ello, siga las instrucciones del documento que se adjunta.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('55', 'DCD.T0000054', 'Cómo configurar switch ubiquiti edgeswitch ', 'técnico', '1. Conectar cable de red a una boca de switch  2. configurar interface de red del notebook con ip del segmento de switch ej. 192.168.1.10  3. En el navegador digitar la que viene por default 192.168.1.2  4. Ingresar user: ubnt  5. Ingresar pass: ubnt    ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('56', 'DCD.T0000055', 'Cómo configurar switch ubiquiti para asignar vlan a un puerto especifico', 'técnico', 'revisar este enlace  https://help.ui.com/hc/en-us/articles/360014198613-EdgeSwitch-EdgeSwitch-X-How-to-Add-VLANs#1', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('57', 'DCD.T0000056', 'Como configurar teléfonos Avaya 9608', 'técnico', '1. Rebootear el teléfono.  2. Presione el botón * para programar cuando se le indique, cuando el teléfono que se está iniciando.  3. Luego en el menú seleccione la opción ADDR  4. Luego seleccionar la opción \"Servidor HTTP\" y asignar la IP de la central 10.6.20.2, guardar cambios  5. Dentro del mismo menú, selecciones \"Servidor HTTPS\" y asignar la IP de la central 10.6.20.2, guardar cambios  6. Dentro del mismo menú, seleccionar \"VLAN\" y asignar el número 20, guardar cambios.  7. Salir al menú principal y seleccionar la opción de reiniciar el teléfono.  8. Cuando haya iniciado el teléfono pedirá que ingrese el número de anexo asignado, considerar que para esta acción solo son unos 5 seg, de lo contrario pasará a conectase a la central sin el anexo, por lo que se debe reiniciar el teléfono nuevamente para ingresar el anexo.  9. Una vez ingresado el anexo se conecta a la central.    Para el reset del teléfono referirse al proceso #USX.PR1388', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('58', 'DCD.T0000057', 'Como configurar un equipo con Windows 10 en GOREOHIGGINS ', 'técnico', 'Para ejecutar este procedimiento, debes conocer:    -el nombre del computador.    -la contraseña de la cuenta GOREOHIGGINS\\Soporte2    Una vez instalado windows te pedirá crear una cuenta, usa el nombre setupuser (deja la contraseña en blanco)  Inicia sesión como setupuser  Abre la consola Usuarios y Grupos locales (ejecuta lusrmgr.msc)   Habilita cuenta administrador o administrator que se encuentra creada.  Cambia la contraseña de administrador local a: maoorf5gujzoe88da   (clic en continuar si aparece la advertencia de cambio de contraseña)  Cambia el nombre de maquina a <NombreComputador>  Inscribir en dominio GOREOHIGGINS (debes usar la cuenta de dominio Soporte2)   Reinicia  Iniciar sesión como goreohiggins\\soporte2  Eliminar cuenta setupuser  Borrar carpeta c:\\usuarios\\setupuser', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('59', 'DCD.T0000058', 'Como configurar una impresora Xerox para que envíe por correo los documentos escaneados ', 'técnico', '', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('60', 'DCD.T0000059', 'Como configurar VPN en Router Edge para que usuarios remotos usen DNS', 'técnico', '1.  Add the virtual tunnel interface to the DNS forwarding interface list.  set service dns forwarding listen-on vtun0    Fuente: https://help.ui.com/hc/en-us/articles/115015971688-EdgeRouter-OpenVPN-Server', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('61', 'DCD.T0000060', 'Como corregir ERROR:There is already a certificate for en la firma de un certificado en OPENVPN', 'técnico', 'Si usted ya ha creado un certificado con el mismo asunto y desea crear uno nuevo, puede realizar una de las tres acciones:    A) Eliminar restricción UNIQUE_SUBJECT  Editar archivo /usr/lib/ssl/misc/demoCA/index.txt.attr modificando unique_subject=yes por unique_subject_no    B) Modificar registro de certificado preexistente.  Editar archivo /usr/lib/ssl/misc/demoCA/index.txt y localiza la linea donde se encuentra el registro del certificado pre-existente, agregue algunos caracteres que puedan hacerlo diferente, por ejemplo:  linea original  V       220326201555Z           1004    unknown /C=CL/ST=SCL/L=RANCAGUA/O=GOREOHIGGINS/OU=TI/CN=angie.pavez/emailAddress=angie.pavez@goreohiggins.cl  linea editada  c  V       220326201555Z           1004    unknown /C=CL/ST=SCL/L=RANCAGUA/O=GOREOHIGGINS/OU=TI/CN=angie.pavez.old/emailAddress=angie.pavez.old@goreohiggins.cl    C) Generar nuevo certificado asegurandose de no repetir el SUBJECT  ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('62', 'DCD.T0000061', 'Como crear certificados Cliente para Open VPN En Router EdgeRouter 8 PRO', 'técnico', 'EdgeRouter 8 PRO #AK7902135  Se debe seguir el siguiente procedimiento del enlace  https://help.ui.com/hc/en-us/articles/115015971688-EdgeRouter-OpenVPN-Server    Conectate al router 10.6.0.1 via putty    sudo su  cd /usr/lib/ssl/misc    ./CA.pl -newreq  ./CA.pl -sign  mv newcert.pem /config/auth/nombre.apellido.pem  mv newkey.pem /config/auth/nombre.apellido.key  openssl rsa -in /config/auth/luis.veliz.key -out /config/auth/nombre.apellido-no-pass.key  mv /config/auth/luis.veliz-no-pass.key /config/auth/nombre.apellido.key  chmod 644 /config/auth/nombre.apellido.key', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('63', 'DCD.T0000062', 'Como crear certificados Servidor para Open VPN En Router EdgeRouter 8 PRO', 'técnico', 'Procedimiento:  <a href=\"https://help.ui.com/hc/en-us/articles/115015971688-EdgeRouter-OpenVPN-Server%E2%80%9D\">  Instalación EdgeRouter - OpenVPN Server</a>    Seguir los pasos de:  1 al 10  12 y 13    Nota: al crear el nuevo certificado se debe incluir el archivo cacert.pen que se encuentra en el router, la ruta es /config/auth  y se debe incluir en el paquete de crecion de vpn para clientes  (procedimiento #USX.PR1347) que se encuentra en el pc-soporte ruta D:\\Software\\VPN\\Configuration-SET-Gen-3', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('64', 'DCD.T0000063', 'Cómo crear grupos de seguridad para carpetas compartidas en Active Directory', 'técnico', 'Para mejorar la administración de AD, se deben crear grupos de recursos en el cual los usuarios se vayan agregando sin necesidad de hacerlo en la carpeta compartida', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('65', 'DCD.T0000064', 'Como crear paquete de configuración VPN para funcionario', 'técnico', 'En el PC de soporte realizar las siguientes acciones:  1) Ejecute el procedimiento #USX.PR1324 Como crear certificados Open VPN En Router EdgeRouter 8 PRO con Putty  2) Una vez creado el certificado en el punto 1, haga una copia de alguna de las carpetas de la ruta \" Z:\\Software\\VPN\\Configuration-SET-Gen-2\\\" y renombre la carpeta con el usuario al cual se creo el certificado, también debe borrar los archivos del certificado de la carpeta config estos son nombre.apellido.key y nombre.apellido.pem  3) Luego copiar los archivos del certificado (nombre.apellido.key y nombre.apellido.pem) que creo en el punto 1 a la carpeta creada con la siguiente nomenclatura VPN.nombre.apellido en la carpeta \"config\" de la ruta Z:\\Software\\VPN\\Configuration-SET-Gen-2\\VPN.nombre.apellido.   4) Modifique el siguiente archivo \"gore.ovpn\" de la carpeta del usuario VPN.nombre,apellido que está en config, de la carpeta que copio de acuerdo al punto dos, cambiando las siguientes lineas a nombre del nuevo usuario, ejemplo  cert nombre.apellido.pem  key nombre.apellido.key  5) Completado el punto 4, genere archivo ZIP con el paquete de configuración.  6) El Archivo ZIP generado se debe copiar a la siguiente ruta del pc de soporte Z:\\www\\soporte\\software\\VPN\\, el cual disponibiliza el archivo en el sitio web http://soporte.goreohiggins.cl:8171/software/vpn/indice.asp', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('66', 'DCD.T0000065', 'Como crear regla de correo para mover mensajes dirigidos a listas de distribucion', 'técnico', 'Inicia sesión en Outlook web usando la cuenta del usuario en cuyo buzón va a crear la regla.    Crea una carpeta cuyo nombre contenga a lo menos haga referencia al nombre del grupo.     <a href=\'https://outlook.office.com/mail/options/mail/rules\' target=\'_blank\'>Crea una regla</a> con los siguientes datos:    a) Nombre: <b>Para todos los mensajes enviados a {Nombre de Grupo}</b>    b) Condición: <b>Para</b> Dirección: <b>{dirección de correo del grupo}</b>    c) Acción: <b>Mover a</b> Carpeta: <b>{Nombre de la carpeta}</b>  Detener el procesamiento de más reglas: <b>ACTIVADO</b>  Ejecutar regla ahora: <b>ACTIVADO</b>  <b>Guardar</b>    En caso que el funcionario use cliente de correo outlook antiguo (2013) es posible que no sea posible sincronizar la carpeta creada en outlook web. Si ese es el caso, intente realizar lo indicado en #USX.PR1463 Como sincronizar carpeta en Outlook 2013 con Exchange 365  Si eso no funciona, habrá que ver la forma de asignarle una licencia estándar, previa validación con su jefatura y los encargados de TI en GoreOhiggins (#Ricardo.Gonzalez o #Carlos.Carrasco)', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('67', 'DCD.T0000066', 'Cómo crear un Apple ID nuevo', 'técnico', 'https://support.apple.com/es-cl/HT204316#ios', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('68', 'DCD.T0000067', 'Como crear un sub-dominio en el DNS de la red interna de GORE', 'técnico', 'Este procedimiento permite tener acceso a sitios desarrollados para GORE y que no son resueltos cuando se llama al sitio desde la red interna', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('69', 'DCD.T0000068', 'Como crear una contraseña de apertura de cerradura DAHUA', 'técnico', 'Este procedimiento aplica a #AK7902073 y #AK7902074    1) Retire la tapa de las baterías, presione el botón de enrolamiento y digite la contraseña de administrador (Solicitar a #oscar.leiva o #claudio)  2) Presione la tecla 1, Luego presione nuevamente la tecla 1, ingrese la clave y presione la tecla #, ingrese la clave nuevamente y presione la tecla #.  3) Resetee para salir del modo de enrolamiento y pruebe abriendo la cerradura con el teléfono.      Más detalles puede encontrar en:  #USX.PR1487 Manual de Usuario de Cerradura Inteligente DAHUA  #USX.PR1486 Manual de Instalación de Cerradura Inteligente DAHUA', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('70', 'DCD.T0000069', 'Como crear una lista de distribución dinámica en Exchange online (ejemplo: todos)', 'técnico', 'Cuando necesite crear listas de distribución en la que los miembros obedecen a un subconjunto de destinatarios basado en criterios de configuración, ustede debe crear listas de distribución dinámicas.  Tras el siguiente enlace, usted puede conocer como crear una nueva lista de distribución dinámica:    <a href=\'https://learn.microsoft.com/en-us/exchange/recipients-in-exchange-online/manage-dynamic-distribution-groups/manage-dynamic-distribution-groups?tabs=create-powershell\' target=\'_blank\'>Manage dynamic distribution groups in Exchange Online</a>    <a href=\'https://admin.exchange.microsoft.com/\' target=\'_blank\'>Centro de administración de Exchange</a>', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('71', 'DCD.T0000070', 'Como definir una contraseña para GOREOHIGGINS', 'técnico', 'Para evitarse tener que estar inventando contraseñas cada vez que lo necesitemos, utiliza el siguiente estándar para definirla:    Dos letras en mayúsculas un guion y seis números, por ejemplo: DF-865431    También, puede usar la siguiente utilidad: <a href=\'genkey.aspx\' target=\'_blank\'/>Generador de Contraseñas GOREOHIGGINS</a>', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('72', 'DCD.T0000071', 'Como desactivar el Solucionador de problemas de mantenimiento del sistema', 'técnico', 'Si ha tenido problemas como el descrito en #USX.EC22122 Icono de acceso directo de archivo o programa de red ha desaparecido, quizás necesite desactivar el solucionador de problemas de mantenimiento del sistema, para evitar que sus accesos directos remotos desaparezcan cuando su equipo no está conectado a la red. Para desactivar el solucionador de problemas de mantenimiento del sistema, sigas los siguientes pasos:  Haga clic en Inicio Botón Inicio de Windows y, a continuación, haga clic en Panel de Control.  En el sistema y seguridad, haga clic en Buscar y corregir problemas.  Nota: si no se muestra el sistema y seguridad necesitará cambiar la vista de Panel de Control. Para cambiar la vista, haga clic en la flecha hacia abajo en la vista por y seleccione la categoría. Ver por se encuentra en la esquina superior derecha del Panel de Control.    Under System and Security, click Find and fix problems.  En el panel de navegación izquierdo, haga clic en Cambiar configuración.  Mantenimiento del equipo se establece en Off.    Fuente: <a href=\'https://support.microsoft.com/es-es/topic/accesos-directos-de-escritorio-desaparecen-en-windows-7-e6efbf49-ee07-a8e4-3d3e-cf27bb7c0b31\' target=\'_blank\'>Articulo</a>', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('73', 'DCD.T0000072', 'Como desactivar el uso de impresoras locales en un conección RDP', 'técnico', 'Para desactivar el uso de impresoras locales en una conección RDP, inicie RDP Client (mstsc), o edite un acceso directo RDP previamente configurado.  En seguida vaya a la pestaña Recursos Locales, y desactive la casilla Impresoras en el grupo Dispositivos y Recursos Locales.  Si ha iniciado el RDP Client (mstsc) puede conectarse de inmediato.  Si está editando un accso directo vaya a la pestaña General y haga clic en el botón Guardar. Y luego puede conectarse si lo desea.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('74', 'DCD.T0000073', 'Como desactivar reenvio de llamadas entrantes', 'técnico', 'Tecla funcion  Reenviar  Reenviar incondicional  Rem.Incodic. -> Desactivar  ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('75', 'DCD.T0000074', 'Como desactivar una lista de distribución de correo Exchange 365', 'técnico', 'El concepto de desactivación de una lista de distribución no existe como tal en Exchange 365, en GOREOHIGGINS se definió que desactivar una lista de distribución es cambiar el nombre agregando la palabra OFF al final, por ejemplo:  Una lista de distribución que se llame <b style=\'color:green\'>Postulación DEPORTE 2021</b> cuyo correo sea <b style=\'color:green\'>postulacion.deporte.2021@goreohiggins.cl</b> pasará a llamarse:  <b style=\'color:red\'>Postulación DEPORTE 2021 (OFF)</b> <b style=\'color:red\'>cuyo correo sea postulacion.deporte.2021@goreohiggins.cl</b>    Se usa esta forma, para evitar que cualquier remitente pueda enviar mensajes a esa casilla, no se elimina la lista porque queda en la lista de eliminados por algunos días, y luego ya no puede restaurarse, y habrán listas de distribución cuyas vigencias pueden cambiar, es decir, son validas hasta una fecha en especifico, y luego, pueden necesitar activarlas hasta otra fecha en especifico.    PASOS:  1) Vaya al Centro de administración de Microsoft 365  2) Vaya a Teams y grupos, Grupos y Equipos Activos, Lista de distribución  3) Seleccione el grupo a desactivar, en el panel de propiedades, haga clic en configuración, y clic en configuración avanzada.  4) Vaya a la opción \"Administración de entrega\", y agregue \"Administrador 365\", esto evitará que usuarios intermos de la organización envíen correos, les rebotará  5) vaya a la seccion general y agregue el texto (OFF) al grupo y guarde los cambios.    Si alguien quisiera enviar un mensaje a la lista recibiría un mensaje como este:  <b>No se pudo entregar el mensaje al grupo nombredegrupo@goreohiggins.cl<b>', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('76', 'DCD.T0000075', 'Como desbloquear o quitar el código de bloqueo de iphone iPhone/iPad/iPod con Tenorshare 4uKey', 'técnico', 'Para desbloquear o quitar el código de bloqueo de un iphone ipad o ipod usando Tenorshare 4uKey siga el ejemplo del siguiente video:  <a href=\'https://www.youtube.com/watch?v=y1YgAUus3Zs\' target=\'_Blank\'>Forgot iPhone Passcode or iPhone is Disabled?How to Unlock it without iTunes?</a>    Deberá tener instalado el software Tenorshare 4uKey en su computador. En este caso se ha instalado en PC-SOPORTE #AK7902261  #USX.PR1385 Como instalar Tenorshare 4uKey para GOREOHIGGINS', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('77', 'DCD.T0000076', 'Como disponibilizar licencias Office365 en GOREOHIGGINS', 'técnico', '', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('78', 'DCD.T0000077', 'Como eliminar paquete de configuración VPN', 'técnico', 'En PC-SOPORTE, eliminar Carpeta del usuario en D:\\Software\\VPN\\Configuration-SET-Gen-2  En PC-SOPORTE, eliminar Archivo zip del usuario en D:\\www\\soporte\\software\\VPN  #USX.PR1331 Revocar certificado del usuario', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('79', 'DCD.T0000078', 'Como enrolar o registrar a una persona en el reloj control', 'técnico', '1) presion boton ok  2) digita el rut del gore 72240400 y presiona ok  3) digita la clave 14997911 y presiona ok  4) Entrar a Users.  5) Nuevo Usr.  6) Digitar rut sin codigo verificador  7) Presionar segunda opcion  (Huella) y enrolar 3 veces el dedo derecho y luego 3 veces el dedo izquierdo  8) Presionar OK  9) Salir (Esc)    Nota: En Google Photos de claudio.lillo.contreras@gmail.com hay un video con un caso de enrolado de #marcos.concha, debe buscar el video con el texto \"USX.PR1511\"', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('80', 'DCD.T0000079', 'Como ensamblar un conector y cable HDMI', 'técnico', '<a href=\'https://www.youtube.com/watch?v=Xub0l9s8O6Y\' target=\'_blank\'>How to assemble a HDMI cable</a> (Duración 8:43)  <a href=\'https://www.youtube.com/watch?v=xwjL_OsomzQ\' target=\'_blank\'>Como armar / ensamblar un cable HDMI l Reparación cable HDMI</a> (Duración 7:09)  ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('81', 'DCD.T0000080', 'Como escalar requerimiento a INGSOFT', 'técnico', '1) Crear ticket GOREOHIGGINS, donde el solicitante es quien envió el correo original y el responsable es un integrante del equipo de soporte en terreno.    2) El responsable de la tarea, debe \"Derivar Tarea a...\" \"Claudio\" y solicitar autorización para realizar el escalamiento.    3) Una vez derivado el ticket al responsable y recibida la autorización, el mismo responsable debe enviar el mensaje original del solicitante a soporte.igestion@ingsoft.freshdesk.com con copia al solicitante, con el asunto con la forma \"Usx.T99999 nombre de tarea.    4) Luego, en el ticket haga \"Derivar Ticket a...\" y elija el nombre \"claudio.guerra\", escriba un texto en el que indica que lo ha derivado al proveedor.    5) De ahí en adelante, el responsable de la tarea, debe dar seguimiento a la misma, y escribir en los comentarios todas las novedades que reciba del caso. (Puede copiar y pegar el correo recibido si lo considera conveniente)', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('82', 'DCD.T0000081', 'Como evitar que sus accesos directos a recursos de red desaparezcan', 'técnico', 'Si ha tenido problemas como el descrito en #USX.EC22122 Icono de acceso directo de archivo o programa de red ha desaparecido, usted puede abordarlo de dos maneras diferentes, revise al documento adjunto para revisar los métodos disponibles para abordarlo.   recomendamos usar el método 1:  Método 1: Quitar todos menos 4 accesos directos rotos desde el escritorio  Mantener el número de accesos directos rotos en el escritorio a cuatro o menos. Puede lograr esto quitando todos pero 4 de sus métodos abreviados más utilizados en el escritorio. Si tiene más de 4 accesos directos, también puede crear una carpeta en el escritorio y mover los accesos directos a la carpeta. No se quitarán estos accesos directos ya que no se sientan directamente en el escritorio.  ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('83', 'DCD.T0000082', 'Como evitar que una cuenta de correo sea clasificado como SPAM o correo no deseado por EXCHANGE 365', 'técnico', 'Para evitar que una cuenta sea clasificada como SPAM o correo no deseado, usted debe realizar los siguientes pasos:  1) Vaya al Centro de administración de Microsoft 365 y agregue la cuenta como contacto  2) Vaya al centro de administración de Exchange 365 y haga clic en Flujo de Mensajes o Mail Flow  3) Agregar nueva regla Bypass mail filtering...  Nombre: <strong>Aceptar-{cuenta-de-correo}</strong>  Aplicar esta regla si: El remitente es  {cuenta-de-correo}  4) Haga clic en Guardar o Save      Fuente: <a href=\'https://itadmins.es/evitar-correo-tratado-como-spam-en-office-365-exchange-online\' target=\'_blank\'>Evitar correo tratado como Spam en Office 365 / Exchange Online</a>', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('84', 'DCD.T0000083', 'Como exportar listado de anexos desde Avaya IP Office Manager', 'técnico', 'Conéctate a la plataforma de Avaya usando el siguiente procedimiento:  #USX.PR1400 Como acceder a Avaya IP Office Manager en GOREOHIGGINS    1. Ingresar a IP Office Manager  2. Seleccionar \"Archivos\"-->\"Opciones Avanzadas\"-->\"System Status\"  3. Ingresar usuarios y clave que se ingresa a IP Office Manager  4. Luego en el menú seleccionar \"Extensions\"  5. Seleccionar    6. Copia el listado de anexos desde la pantalla y pega los datos en un archivo Excel, el archivo debe cumplir con lo especificado en #Usx.F3025', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('85', 'DCD.T0000084', 'Como exportar listado de cuentas con espacio usado en buzón de correo Microsoft 365 Exchange', 'técnico', 'En cualquier computador con acceso a internet:  1. Inicie PowerShell como Administrador  2. Inicia sesión en Microsoft 365 (#USX.PR1303 Cómo iniciar sesión en PowerShell para Exchange on line)  3. Ejecuta la siguiente sentencia:      get-mailbox | get-mailboxstatistics | Select  DisplayName, Totalitemsize | Export-Csv -Encoding UTF8 \"C:\\UserMailboxSizes.csv\" -NoTypeInformation    El archivo generado producirá un listado con los usuarios y el uso de su buzón de correo, ejemplo:  \"Alias\",\"DisplayName\",\"TotalItemSize\"  ,\"Aldo Herrera Rosas\",\"18.38 GB (19,738,303,099 bytes)\"  ,\"Alejandro Romero\",\"578.8 MB (606,922,489 bytes)\"  ,\"Alex Raul Ramirez Ortiz\",\"264.9 MB (277,781,232 bytes)\"', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('87', 'DCD.T0000086', 'como exportar listas de distribución Exchange', 'técnico', '1. conectarse al pc de soporte  2. ejecutar powershell como administrador  3. ejecutar el siguiente comando para conectarse \"Connect-ExchangeOnline\" sin las comillas  4. coloque su cuenta de dominio con sus credenciales  5. ejecute la siguiente sentencia:    la lista a exportar es Asociación de Funcionarios20210205194359 la dejara en un archivo txt  Get-DistributionGroupMember -Identity \"Asociación de Funcionarios20210205194359\" | Select Name, RecipientType, PrimarySMTPAddress | Export-csv -path D:\\20240306asociacionfuncionariosgore.txt    el grupo a exportar es goreohiggins  Get-DistributionGroupMember -Identity \"Funcionarios Gobierno Regional de O\'Higgins\" | Select Name, RecipientType, PrimarySMTPAddress | Export-csv -path D:\\20240306funcionariosgore.txt    lista Funcionarios Honorarios Gobierno Regional de O\'Higgins  Get-DistributionGroupMember -Identity \"Funcionarios Honorarios Gobierno Regional de O\'Higgins\" | Select Name, RecipientType, PrimarySMTPAddress | Export-csv -path D:\\20240306funcionarioshonorarios.txt  en caso de que quiera exportar otra lista debe reemplazar el grupo que esta entre \"comillas\"', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('88', 'DCD.T0000087', 'Cómo exportar miembros del grupo de Active Directory con Powershell (Get-ADGroupMember)', 'técnico', 'En el PC de Soporte se debe realizar lo siguiente:    1. Ejecutar PowerShell como administrador  3. Ejecutar la siguiente sentencia:  Get-ADGroupMember -identity “nombredegrupo” -recursive | select name | Export-csv -path D:\\nombredegrupo.csv –NoTypeInformation      ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('89', 'DCD.T0000088', 'Como exportar usuarios con licencias Office365 en PowerShell', 'técnico', '1. Ejecutar PowerShell en modo administrador en el servidor Controlador de  Dominio:  rcgua-dc-06.goreohiggins.cl [10.6.2.12]  2. Luego ejecute  - Connect-MsolService  3. Ingrese el usuario de dominio con privilegios  - Nombre.usuario@goreohiggins.cl  - password  4. Ejecute la siguiente sentencia para exportar los usuarios con licencia.  - Get-MSOLUser | Where-Object { $_.isLicensed -eq \"True\"} | Select-Object DisplayName, UserPrincipalName, isLicensed | Export-Csv C:\\LicensedUsers.csv', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('90', 'DCD.T0000089', 'como extraer información de vcenter o vmware', 'técnico', 'herramienta para sacar información de las maquinas virtuales creadas en los servidores vmware  bajar e instalar  https://www.robware.net/rvtools/download/  al ejecutar se debe colocar la IP el usuario y pass , como si estuviéramos ingresando por web, luego menu archivo y guardar la información', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('91', 'DCD.T0000090', 'Como extraer usuarios de lista de distribución de AD (Exchange)', 'técnico', '1. Ejecutar PowerShell como administrador  2. Conectarse a Exchange on line con la siguiente sentencia Connect-ExchangeOnline (debe ingresar sus credenciales de dominio)  3. Ejecutar la siguiente sentencia:  Get-DistributionGroupMember -Identity \"Funcionarios Gobierno Regional de O\'Higgins\" | select name, PrimarySmtpAddress | Export-csv -path D:\\usergrupogore.csv  4. Disconnect-ExchangeOnline', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('92', 'DCD.T0000091', 'Como firmar un PDF con firma electrónica avanzada de E-CERTCHILE', 'técnico', 'Para firmar un documento PDF con firma electrónica avanzada con E-CERTCHILE siga las instrucciones en el documento adjunto.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('93', 'DCD.T0000092', 'Como generar archivo F3062 exportando listado de direcciones IP concedidas por un DHCP', 'técnico', 'Conéctate al servidor DHCP vía escritorio remoto (ejecute mstsc -v:<ipservidor>)  Inicia una consola de PowerShell en modo Administrador  Ejecuta la siguiente sentencia:  Get-DHCPServerV4Scope | ForEach ($ScopeID) {Get-DHCPServerv4Lease -ScopeID $_.ScopeID}| Export-Csv -path C:\\Temp\\Usx.F3062.$env:computername.csv    Envía el archivo a goreohiggins@archive.usx.cl con el asunto Usx.F3062    #Usx.F3062 Archivo DHCPServerV4Scope', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('94', 'DCD.T0000093', 'Como generar archivo F3066 exportando configuracion de Avaya IP Office Manager', 'técnico', 'Este procedimiento muestra como generar el archivo #Usx.F3066, con toda la configuración de la plataforma de AVAYA IP Office Manager en GOREOHIGGINS.  En el documento que se adjunta a este procedimiento se hace referencia a:  #USX.PR1400 Como acceder a Avaya IP Office Manager en GOREOHIGGINS y por lo tanto necesitará conocer la contraseña de acceso a la administración de esa plataforma.  PC-SOPORTE, D:\\Backup\\Avaya IP Office', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('95', 'DCD.T0000094', 'Como generar el listado de marcaje vs asistencia', 'técnico', 'Para generar el #Usx.F3112 Listado de marcaje vs asistencia de un mes para todos los funcionarios activos se debe ejecutar el siguiente procedimiento.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('96', 'DCD.T0000095', 'Como generar reporte de mensajes enviados a un destinatario en Exchange 365', 'técnico', 'Para este procedimiento necesitas:  -Usuario y contraseña con acceso a Exchange Admin Center  -Identificador de la solicitud  -Lista de destinatarios  -Rango de fechas para el reporte    1) Vaya a Exchange admin center  2) En el panel izquierdo expande <b>Mail Flow</b> y haz clic en <b>Message trace</b>  3) En el panel derecho haz clic en <b>Downloadable Reports</b> y haz clic en <b>Start Trace</b>  4) En el cuadro de texto <b>Recipients</b>, escribe la o las direcciones de correo de los destinatarios.  5) Haz clic en <b>Custom time range</b> y establece el rango de fechas requeridas.  6) En la sección <b>Report type</b> seleccione <strong>Extended Report</strong>y haga clic en el botón <b>Next</b>  7) En el cuadro de texto <b>Report Title</b> escriba el identificador del Ticket donde se hizo la solciitud.  8) En el cuadro de texto <b>When the report is ready to download the email below will be notified</b> escriba <b>TI@goreohiggins.cl</b> y haga clic en el botón <b>Prepare report</b>  9) Luego ingrese un comentario en la tarea indicando que ha sido configurado el reporte solicitado y programe su revisión para el día siguiente.  FIN', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('97', 'DCD.T0000096', 'Como generar reporte de mensajes enviados por un remitente en Exchange 365', 'técnico', 'Para este procedimiento necesitas:  -Usuario y contraseña con acceso a Exchange Admin Center  -Identificador de la solicitud  -Lista de remitentes  -Rango de fechas para el reporte    1) Vaya a Exchange admin center  2) En el panel izquierdo expande <b>Mail Flow</b> y haz clic en <b>Message trace</b>  3) En el panel derecho haz clic en <b>Downloadable Reports</b> y haz clic en <b>Start Trace</b>  4) En el cuadro de texto <b>Senders</b>, escribe la direccion de correo del remitente.  5) Haz clic en <b>Custom time range</b> y establece el rango de fechas requeridas.  6) En la sección <b>Report type</b> seleccione <strong>Extended Report</strong>y haga clic en el botón <b>Next</b>  7) En el cuadro de texto <b>Report Title</b> escriba el identificador del Ticket donde se hizo la solciitud.  8) En el cuadro de texto <b>When the report is ready to download the email below will be notified</b> escriba <b>TI@goreohiggins.cl</b> y haga clic en el botón <b>Prepare report</b>  9) Luego ingrese un comentario en la tarea indicando que ha sido configurado el reporte solicitado y programe su revisión para el día siguiente.  FIN', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('98', 'DCD.T0000097', 'Como habilitar escritorio remoto (RDP) a funcionarios del goreohiggins', 'técnico', 'Para este procedimiento usted debe conocer el nombre del equipo o la dirección al que se desea acceder vía RDP y la cuenta de usuario del funcionario.    Solicite reserva de IP para el equipo al que se desea acceder vía RDP.  Solicite agregar la cuenta del funcionario al grupo RD-Usuariosremotos.    Mientras, habilite acceso remoto en el equipo al que desea conectarse.    Por otro lado, debe configurar el equipo desde el que se conectará el funcionario.    - Inicio > Configuración    > Sistema > escritorio remoto y active Habilitar escritorio remoto.    - Se debe comprobar que la opción:       \"Permitir solo las conexiones desde equipos que ejecuten Escritorio remoto con Autentificación a nivel de red(recomendado).\"      Acá usted debe configurar la VPN con el certificado del funcionario y agregar un acceso directo para acceder vía RDP al computador del funcionario.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('99', 'DCD.T0000098', 'Cómo habilitar Instrumental de administración de Windows (WMI) en la PC', 'técnico', 'Estas reglas permiten a un administrador obtener información del sistema operativo de manera remota, esto permitirá por ejemplo, conocer si el servicio TermServices está activo.    Con una cuenta con privilegios de administración, abre la consola de administración de Windows Firewall seguridad avanzada.  Abre reglas de Entrada  Selecciona las DOS reglas de entrada llamadas \"Instrumental de administración de Windows (WMI de entrada)\" y habilitalas.    ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('100', 'DCD.T0000099', 'Como habilitar modulo ExchangeOnline en powershell ', 'técnico', 'Abre una ventana de PowerShell en modo administrador y ejecuta cada uno de estos comandos.    Install-Module -Name ExchangeOnlineManagement -RequiredVersion 2.0.3  Set-ExecutionPolicy RemoteSigned  Install-Module -Name ExchangeOnlineManagement  Update-Module -Name ExchangeOnlineManagement  Import-Module ExchangeOnlineManagement', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('101', 'DCD.T0000100', 'Como habilitar modulo powershell ActiveDirectory en windows 10', 'técnico', 'A partir de la actualización de octubre de 2018 de Windows 10, RSAT se incluye como un conjunto de \"Funciones bajo demanda\" directamente en Windows 10. No descargue un paquete RSAT de esta página. En su lugar, simplemente vaya a \"Administrar funciones opcionales\" en Configuración y haga clic en \"Agregar una función\" para ver la lista de herramientas RSAT disponibles. Seleccione e instale las herramientas RSAT específicas que necesite. Para ver el progreso de la instalación, haga clic en el botón Atrás para ver el estado en la página \"Administrar características opcionales\".    Botón Buscar, \"Agregar una característica opcional\"  Agregar Característica opcional  Buscar: RSAT: herramientas de Active Directory Domain Services y Lightweight Directory Services    Fuente: <a href=\'https://www.microsoft.com/es-ES/download/details.aspx?id=45520\'>Herramientas de administración remota del servidor para Windows 10</a>', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('102', 'DCD.T0000101', 'Como habilitar opción AllowPlusAddressInRecipients en Exchange de GOREOHIGGINS', 'técnico', 'Inicia una sesión de PowerShell en modo administrador y ejecuta los siguientes comandos uno por uno, necesitarás la contraseña de administrador365@goreohiggins.cl    Connect-ExchangeOnline -UserPrincipalName administrador365@goreohiggins.cl -ShowProgress $true  Set-OrganizationConfig -AllowPlusAddressInRecipients $true  Disconnect-ExchangeOnline', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('103', 'DCD.T0000102', 'Como habilitar PC para la emisión de liquidaciones en PDF en PYR (INGSOFT) usando PDF Creator', 'técnico', 'Descarga el instalador desde:  http://soporte.goreohiggins.cl:8171/software/PDFCreator/4.2.0/PDFCreator-4_2_0-Setup.exe    Descarga el configurador desde:  http://soporte.goreohiggins.cl:8171/software/PDFCreator/4.2.0/Config.PYR.ini.zip', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('104', 'DCD.T0000103', 'Como habilitar RSAT en Windows 10 (Remote Server Administrator Tools) ', 'técnico', 'En el documento adjunto, podrá encontrar dos maneras de habilitar esta aplicación.    Si está usando las versiones más recientes de Windows 10, use la manera nueva de habilitar esta característica.    Buscar \"Agregar o Quitar Programas\"  Seleccione \"Aplicaciones y Características\"  Seleccione \"Características Opcionales\"  Busque \"RSAT\"  Clic en \"RSAT: administrador del servidor\" para instalar  Clic en \"RSAT: herramientas de Active Directory Domain...\" para instalar    Si aparece el botón desinstalar, es porque ya está instalado.  Depende de lo que necesite', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('105', 'DCD.T0000104', 'Como habilitar speedtest en un ubiquiti routeredge', 'técnico', '1. Ingresar a la consola del gateway  2. Ejecutar comando sudo su  3. ejecuta el comando curl -O https://raw.githubusercontent.com/sivel/speedtest-cli/master/speedtest.py   4. ejecuta el comando chmod a+rx speedtest.py  5. ejecuta el comando mv speedtest.py /usr/bin/speedtest-cli  6. puedes probar que funciona ejecutando el comando: speedtest-cli --no-pre-allocate', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('106', 'DCD.T0000105', 'Como habilitar una dirección de correo como originador autorizado en una lista de distribución', 'técnico', 'Este procedimiento describe los pasos necesarios para habilitar una dirección de coreo como originador autorizado en una lista de distribución. Si a usted le corresponde realizar este procedimiento, debe primero determinar el tipo de lista de lista de distribución:   a) Lista de Distribución Universal de Active Directory  b) Lista de Distribución Microsoft 365  c) Grupo Microsoft 365     Si corresponde a una Lista de Distribución Universal de Active Directory:  1) Inicia sesión con una cuenta administrador de dominio en PC-SOPORTE   2) Inicia la aplicación Editor ADSI y conecta con el dominio goreohiggins.cl (#USX.SW1035 Editor ADSI (adsiedit.msc))  3) Expande el nodo DC=goreohiggins,DC=cl / OU=GruposDistribucion  4) Abre el cuadro de propiedades del grupo de distribucion   5) En la hoja editor de Atributos selecciona el atributo authOrig y haz clic en editar o doble clic  6) Agrega una nueva entrada con el siguiente formato:     CN={nombre del usuario},CN=Users,DC=goreohiggins,DC=cl     Tambien, puedes localizar al usuario en el nodo CN=Users, abrir el cuadro de propiedades y abrir el atributo distinguishedName y copiar la cadena completa.    Si corresponde a un grupo en microsoft 365, siga lo indicado en el procedimiento #USX.PR1386 Como asignar permiso para que una cuenta pueda enviar un mensaje a un grupo Microsoft 365', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('107', 'DCD.T0000106', 'Cómo habilitar VPN Zerotier', 'técnico', '1. Se debe instalar aplicación zerotier (https://www.zerotier.com/download/)en ambas maquinas (pc o notebook y servidor.  2. Luego ingresar al sitio https://www.zerotier.com/ con la cuenta admin@tech.goreohiggins.cl y su password (solicitarla a #claudio u #oscar.leiva)  3. Se debe sacar el ID definido del sitio en el menú Network.  4. Una vez con el ID se debe unir (Join Network en el icono que está cerca del reloj en la barra de tareas) en cada pc o notebook y servidor (los dos extremos)  5. Cuando se hayan unido a la Network, se debe ir al sitio menú Network, bajar y activar los dos dispositivos nuevos que tendrán comunicación.  ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('108', 'DCD.T0000107', 'Como Hacer una transferencia atendida Teléfono J129', 'técnico', 'Ocurre una transferencia atendida cuando pone una llamada  activa en espera y establece una segunda llamada con el  destinatario de la transferencia de llamada antes de transferir  la llamada.    1. Mientras la llamada esté activa, presione la tecla  Transferir.  2. Realice una de las siguientes acciones para llamar al  destinatario de la transferencia de llamada.  • Marque el número usando el teclado.  • Llame a la persona de la lista Contactos o de la lista  de Recient..  La llamada activa se pone en espera, y la segunda  llamada empieza a sonar. El destinatario de la  transferencia de llamada responde la llamada.  3. Para finalizar la transferencia, presione la tecla Complet..  El teléfono transfiere la llamada al número seleccionado.  Nota:  En el entorno Avaya Aura®  , si el administrador activa  la función Transfer on Hang-Up (Transferir al colgar),  usted puede desconectar la llamada para finalizar la  transferencia  ------------------------------------------------------------------------------------------  Ocurre una transferencia no atendida cuando transfiere una  llamada activa sin establecer una llamada con el destinatario  de la transferencia de llamada.    1. Mientras la llamada esté activa, presione la tecla  Transferir.  2. Realice una de las siguientes acciones para llamar al  destinatario de la transferencia de llamada.  • Marque el número.  • Llame a la persona de la lista Contactos o de la lista  de Recient..  La llamada activa se pone en espera, y la segunda  llamada empieza a sonar.  3. Para finalizar la transferencia, presione la tecla Complet..  El teléfono transfiere la llamada al número seleccionado.  Nota:  • Las transferencias sin responder pueden volver al  teléfono como transferencia de rellamada.  ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('109', 'DCD.T0000108', 'Como hacer una transferencia de llamadas Teléfono 9608', 'técnico', 'Puede transferir llamadas incluso si no hay botones de línea disponibles.    
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('110', 'DCD.T0000109', 'Cómo identificar a que grupos de AD pertenece un usuario por línea de comandos', 'técnico', '1. Ingresar a uno de los controladores de dominio   rcgua-dc-05.goreohiggins.cl [10.6.10.12]  rcgua-dc-06.goreohiggins.cl [10.6.2.12]  2. Ejecutar Windows PowerShell  3. Digitar (copiar) la siguiente línea de comandos, Get-ADPrincipalGroupMembership oscar.leiva | Select name ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('111', 'DCD.T0000110', 'Como Ingresar al portal de RRHH, personal y remuneraciones PYR', 'técnico', 'Ingresa al portal de RRHH, personal y remuneraciones PYR:     http://10.6.1.41/rrhh/    con tu rut (sin puntos ni guion)    contraseña, primeros 4 dígitos de tu rut         y luego te pedirá crear una nueva contraseña.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('112', 'DCD.T0000111', 'Como iniciar la aplicación Configuración de ExtractorTime', 'técnico', '1) Inicia una sesión remota RDP al servidor GORE-DAF-SRV02 (10.6.1.41)  2) Abre el explorador de Windows y abre la carpeta C:\\Program Files\\Extractor de Tiempo  3) Inicia el aplicativo ejecutando el archivo ExtractorTime.exe    Nota: <b style=\'color:red\'>Al abrir el aplicativo, siempre modifica el valor del puerto de SQL Server, estableciéndolo en 1433, lo cual está mal, si ha abierto el aplicativo para modificar algún valor, asegúrate de establecer el puerto en 51618<b/>', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('113', 'DCD.T0000112', 'Cómo iniciar sesión en PowerShell para Exchange on line', 'técnico', 'Se debe ejecutar la siguiente sentencia en PowerShell como administrador  Connect-ExchangeOnline  Aparecerá el logon en el cual se ingresa el:  usuario: administrador365@goreohiggins.cl  Pass: Solicitar a Claudio Lillo u Oscar Leiva', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('114', 'DCD.T0000113', 'Como iniciar sesion superadmin en reloj control', 'técnico', '1) presion boton ok  2) digita el rut del gore 72240400 y presiona ok  3) digita la clave 14997911 y presiona ok  ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('115', 'DCD.T0000114', 'Como instalar AdminCD_11_1_SP1 Build 95 para administración telefónica', 'técnico', '1 Copiar el archivo comprimido que se encuentra en el disco d: de soporte en donde lo quiere instalr  2. Descomprima  3. Luego busque el setup y hacer doble click  4. Se genera un acceso directo llamado Manager', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('116', 'DCD.T0000115', 'Como instalar ADOBE ACROBAT PRO DC en GOREOHIGGINS', 'técnico', 'Primero que nada el usuario al cual se le instalara #USX.SW1030 Adobe Acrobat Pro DC debe tener licencia para poder descargarlo, tener acceso al correo electrónico del funcionario y ademas deben estar todos los programas cerrados     Ingresar a https://creativecloud.adobe.com/  Click en iniciar sesión  Ingresar correo electrónico del funcionario  Es posible que nos envíen un código de 6 dígitos al correo del usuario, es por ello que debemos tener previamente acceso a ese correo, de ser asi ingresar el codigo en el sitio web (no siempre pasa)  Luego de eso nos solicitara la contraseña  Si ingresamos bien los datos, nos mostrara en pantalla una foto de perfil generada por el sistema a la cual debemos hacer click e ingresar donde dice \"ver cuenta\"  Mas abajo hay un recuadro gigante en donde dice \"Tus aplicaciones\" dentro de ese recuadro encontraras un pequeño boton \"accede a tus aplicaciones y servicios\", lo presionas  Al presionar ese boton nos enviara a otro sitio en donde en la parte superior derecha hay otro boton que nos dice \"Obtener Acrobat DC escritorio\", presionamos  Luego de eso la pagina se nos recargara y nos aparece el siguiente mensaje el cual solo debemos presionar el boton \"OK\"    \"Puede necesitarse permiso  Es posible que tengas que solicitar permiso del administrador de TI para poder usar esta aplicación o este servicio\"    Le damos en ok y comenzara la descarga  Luego de eso ejecutamos el instalador y es como instalar un programa común y corriente, siguiente, siguiente, siguiente...  Después de eso nos preguntara si queremos que sea nuestro gestor de PDF predeterminado, damos que si   Y listo', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('117', 'DCD.T0000116', 'Como instalar Antivirus en forma manual', 'técnico', '1. Ejecutar Tecla de Windows + R para abrir el cuadro de diálogo de Ejecutar.  2. Coloque la siguiente ruta \\\\rcgua-dc-06\\kes_remote_installation (enter)  3. Ejecute el instalador \"Kaspersky_Endpoint_Security_for_Windows_(11.8.0)_(11.8.0.384)\"    Referencia Software #USX.SW1032', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('118', 'DCD.T0000117', 'Como instalar AUTOCAD LT en un equipo de GOREOHIGGINS', 'técnico', '1) Inicia sesión en AUTODESK     URL: https://manage.autodesk.com     USR: admin@tech.goreohiggins.cl     PSW: ******** (solicitar a Claudio Lillo)    2) Vaya a Productos y Servicios - >Todos los Productos y Servicios      En el panel derecho haga clic en AUTOCAD LT      En la sección descargas localice la que le interese, usualmente es la primera.      Descargue el producto e instálelo.    3) Una vez instalado debe iniciar sesión con la cuenta del usuario al que se le asignó la licencia, si el usuario no tiene la licencia asignada, debe solicitar autorización a #carlos.carrasco', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('119', 'DCD.T0000118', 'Como instalar Google Earth Pro 7.3 en Windows', 'técnico', 'Use la siguiente URL para iniciar la instalación del producto #USX.SW1014  https://www.google.com/earth/download/gep/agree.html', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('120', 'DCD.T0000119', 'Como instalar java en internet explorer', 'técnico', 'Instalar Java en Internet Explorer  Abra el icono de Internet Explorer y vaya a <a href=\'https://www.java.com/\' target=\'_blank\'>Java.com</a>.    Selecciona el botón Descarga gratuita de Java y después Aceptar e iniciar la descarga gratuita. Si te piden una contraseña de administrador o confirmación, escribe la contraseña o proporciona la confirmación.    En la barra de notificación, selecciona Ejecutar. Si se te pide una contraseña de administrador o una confirmación, escribe la contraseña o proporciona la confirmación.    Selecciona Instalar > Cerrar.    Si tiene problemas para instalar o usar Java, busque respuestas en el Centro de Java ayuda.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('121', 'DCD.T0000120', 'Como instalar modulo powershell de Azure y desinstalar AzureRM', 'técnico', 'Los modulos AZ y AzureRM son incompatibles, Microsoft a reemplazado AzureRM con AZ.    PS C:\\>Install-Module -Name Az -AllowClobber -Scope AllUsers   PS C:\\>Uninstall-AzureRm    Fuente:  <a href=\'https://docs.microsoft.com/en-us/powershell/azure/uninstall-az-ps?view=azps-5.4.0#uninstall-the-azurerm-module\'>Desinstalar AzureRM</a>  <a href=\'https://azure.microsoft.com/es-es/blog/azure-powershell-cross-platform-az-module-replacing-azurerm/\'>Azure PowerShell – Cross-platform “Az” module replacing “AzureRM”</a>', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('122', 'DCD.T0000121', 'Como instalar SafeNet Authentication Client para Firma Electrónica Avanzada con e-Token de E-Cert Chile', 'técnico', 'En el documento adjunto se muestran los pasos necesarios para habilitar un computador para poder usar firma electrónica avanzada con e-Token de e-Cert Chile.  Usted necesitará:  Tener acceso administrativo al PC donde debe instalarlo  El PC donde se instala debe tener acceso a Internet a la URL https://www.e-certchile.cl/  Deberá cambiar la contraseña, debe conocer la contraseña que le proporcionaron al momento de retirar el e-Token ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('123', 'DCD.T0000122', 'Como instalar Tenorshare 4uKey para GOREOHIGGINS', 'técnico', '-Se debe descargar la versión reciente del software en su pagina oficial:  https://www.tenorshare.net/es/products/4ukey-unlocker.html?gclid=CjwKCAiAjoeRBhAJEiwAYY3nDFSi6TPk7glreKZG53uyYpHOoP5KpURvoaYSUDKg2p3eQd3FpHAwXhoC1GQQAvD_BwE    -Una vez descargada se debe abrir el ejecutable y seleccionar Instalar.  -Luego damos iniciar a la aplicación y tendremos el panel principal de la versión gratuita.  -Arriba podemos ingresar la licencia si se encuentra vigente  ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('124', 'DCD.T0000123', 'Como instalar visor de archivos AUTOCAD DWG True View (Reemplazo de DWGSee CAD)', 'técnico', 'Vaya a la siguiente URL y descargue el instalador  https://www.autodesk.com/products/dwg-trueview/overview    Luego realice la instalación de la aplicación.  ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('125', 'DCD.T0000124', 'como modificar copia de seguridad a incremental en Windows Server', 'técnico', '1. abrir programa copia de seguridad Windows Server (herramientas)  2. en la ventana lateral derecha llamada \"Acciones\", seleccionar \"configurar opciones de rendimiento\"  3. seleccione personalizar  4. seleccione en forma individual cada disco (de los que está respaldando)  5. una vez seleccionado, vaya a la columna \"Opción de copia de seguridad\"  6. seleccione \"Copia de seguridad incremental\"  7. luego seleccione Aceptar', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('126', 'DCD.T0000125', 'Como modificar el intervalo de ejecución del proceso ExtractorTime', 'técnico', '1) Inicia la aplicación Configuración de ExtractorTime (Ver #USX.PR1349)  2) Modifica el intervalo de tiempo definido (Viñeta General)  3) Valida que los datos se hayan guardado abriendo el archivo Configuration.xml, allí verás el nodo Parameters con los atributos Termino e Inicio con los valores ingresados.  4) Re-iniciar el servicio ExtractorTime (Ver #USX.PR1352)  5) Cierra las aplicaciones y cierra la sesión RDP.  ---', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('127', 'DCD.T0000126', 'Cómo obtener la key UNMS para aplicar en equipos switch', 'técnico', '1. Ingresar a la URL de Administración https://goreohiggins.unmsapp.com/nms/login  2. Ir a la opción Devices (Lado derecho)  3. Ir a la opción ADD Devices (Lado izquierdo parte superior)  4. Seleccionar la opción Copy UNMS Key to clipboard', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('128', 'DCD.T0000127', 'Como obtener listado de personas de PYR', 'técnico', 'Vaya a la siguiente URL: http://soporte.goreohiggins.cl:8171/api/pyr/exe.asp?method=listado-personas    <a target=\'_blank\' href=\'http://soporte.goreohiggins.cl:8171/api/pyr/exe.asp?method=listado-personas\'>Enlace</a>', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('129', 'DCD.T0000128', 'Como obtener listado de usuarios de Active Directory por PowerShell (enable-disable)', 'técnico', 'En el PC de Soporte se debe realizar lo siguiente:    1. Inicie PowerShell como Administrador  2. Ejecute la siguiente sentencia:  Get-ADUser -Filter * | Ft Name, UserPrincipalName, Enabled | out-file c:\\nombredelarchivo.csv', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('130', 'DCD.T0000129', 'Como obtener miembros de Grupo Exchange del tipo Microsoft 365 con PowerShell', 'técnico', 'Connect-ExchangeOnline -UserPrincipalName administrador365@goreohiggins.cl -ShowProgress $true  Get-UnifiedGroup -Identity \"asociacion.funcionarios@goreohiggins.cl\" | Get-UnifiedGroupLinks -LinkType Member | select name | Export-csv -path D:\\filename1.csv  Disconnect-ExchangeOnline', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('131', 'DCD.T0000130', 'Como otorgar permiso de enviar como o enviar en nombre de a un miembro de un grupo Exchange 365', 'técnico', 'Un miembro de un Microsoft 365 a quien se le hayan concedido permisos Enviar como o Enviar en nombre puede enviar correo electrónico como grupo o en nombre del grupo. (No se pueden conceder estos permisos a los invitados del grupo).   
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('132', 'DCD.T0000131', 'Como parear aplicación del teléfono con cerradura DAHUA', 'técnico', 'Este procedimiento aplica a #AK7902073 y #AK7902074    1) Retire la tapa de las baterías, presione el botón de enrolamiento y digite la contraseña de administrador (Solicitar a #oscar.leiva o #claudio)  2) Presione la tecla 4, y acerque el teléfono con la aplicación Smart Lock instalada.  3) Resetee para salir del modo de enrolamiento y pruebe abriendo la cerradura con el teléfono.      Más detalles puede encontrar en:  #USX.PR1487 Manual de Usuario de Cerradura Inteligente DAHUA  #USX.PR1486 Manual de Instalación de Cerradura Inteligente DAHUA', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('133', 'DCD.T0000132', 'Como permitir acceso a segmento desde OPEN VPN ', 'técnico', 'Este procedimiento se utiliza para cuando sea requerido incluir un nuevo segmento al cual llegar cuando los usuarios se conectan a la red de goreohiggins via OPEN VPN. Esta configuación se puede ver y aplicar en el equipo ROUTER EDGE (10.6.0.1) en la siguiente ruta:     [Config Tree] -> [Configuration] -> [interfaces] -> [openvpn] -> [vtun3] -> [server] : Server -> ADD (Agregar segmento), posterior a esto y aplicar cambios se reinicia el router.      ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('134', 'DCD.T0000133', 'Como proceder con equipos personales para uso del servicio en GOREOHIGGINS', 'técnico', 'cuando se hace alguna configuración en algún equipo de carácter personal que esde propiedad del funcionario se deja constancia en el word que les envió donde se indican con unos simples campos si el equipo es del servicio o personal, y un campo final con el detalle que fue lo que se configuro, email, vpn, office, etc.  para los equipos del servicio sería el mismo formato    y en los párrafos queda establecido de que informática no se responsabiliza por los datos personales e información que exista en el dispositivo.    al final va un campo de firma del funcionario y un VB de informática de la configuración realizada.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('135', 'DCD.T0000134', 'Como proporcionar asistencia remota en windows 10', 'técnico', 'En reemplazo de Teamviewer y con sistemas operativos Windows 10 usted puede proporcionar asistencia remota a un usuario siguiendo las instrucciones presentes en el documento adjunto.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('136', 'DCD.T0000135', 'Como realizar la identificación y registro de ASSETS de un puesto de trabajo', 'técnico', '1) visita el puesto de trabajo y cuenta los dispositivos que debes etiquetar.  2) pregunta a que hora puedes venir en el día (con seguridad) para tomar inventario, considera solo 15 minutos para la toma de inventario.  3) Al visitar el lugar, y por cada dispositivo:     a) asegúrate que no tenga una etiqueta, si la tiene pasa al paso c.     b) adhiere la etiqueta al dispositivo     c) fotografía el dispositivo en esta secuencia.         i) foto al código         ii) foto de cuerpo completo         iii) foto al lugar donde se encuentra marca modelo y serie del dispositivo.  4) abandona el lugar indicando al funcionario que su lugar de trabajo ya está disponible.  5) en tu puesto de trabajo, registra la información capturada en el set fotográfico de cada dispositivo.  ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('137', 'DCD.T0000136', 'Como realizar Limpieza archivos WinSxS Windows 7 o Windows 10', 'técnico', 'Para Windows 7  DISM /online /Cleanup-Image /SpSuperseded                     Para Windows 10  Dism.exe /online /Cleanup-Image /StartComponentCleanup    Fuente: <a href=\'https://learn.microsoft.com/en-us/windows-hardware/manufacture/desktop/clean-up-the-winsxs-folder?view=windows-11\' target=\'_blank\'>Clean Up the WinSxS Folder</a>', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('138', 'DCD.T0000137', 'Como realizar mantenimiento de un proyector', 'técnico', 'Su proyector requiere poco mantenimiento para funcionar en óptimas condiciones.    Es posible que tenga que limpiar la lente periódicamente, y limpiar el filtro y las salidas de aire para evitar que el proyector se sobrecaliente porque la ventilación ha sido bloqueada.  Las únicas piezas que debe reemplazar son la lámpara, el filtro de aire y las pilas del control remoto. Si necesita reemplazar alguna otra pieza, comuníquese con el fabricante o con un técnico autorizado del fabricante.    Advertencia: Antes de limpiar cualquier pieza del proyector, apáguelo y desconecte el cable de alimentación. Nunca abra ninguna tapa del proyector a menos que así se especifique en este manual. El voltaje eléctrico dentro del proyector es peligroso y puede causar graves lesiones.  Advertencia: No intente reparar este producto usted mismo, con excepción de lo descrito específicamente en este manual. Contrate técnicos cualificados para llevar a cabo todas las reparaciones necesarias.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('139', 'DCD.T0000138', 'Como realizar mantenimiento de un proyector - Limpieza de la lampara', 'técnico', 'El proyector lleva un registro del número de horas de uso de la lámpara y muestra esta información en el sistema de menús del proyector.    Reemplace la lámpara lo antes posible cuando ocurra lo siguiente:  Se oscurece o se empieza a deteriorar la imagen proyectada.  Aparece un mensaje al encender el proyector indicándole que reemplace la lámpara.  El indicador de la lámpara parpadea de color naranja y el indicador de encendido parpadea de color azul.    Fuente: https://files.support.epson.com/docid/cpd3/cpd39529/source/maintenance/concepts/maint_lamp.html    #USX.PR1472 Como realizar mantenimiento de un proyector', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('140', 'DCD.T0000139', 'Como realizar mantenimiento de un proyector - Limpieza de la lente', 'técnico', 'Limpie periódicamente la lente del proyector o cada vez que observe polvo o manchas en su superficie.  Para quitar polvo o manchas, limpie la lente suavemente con papel para limpiar lentes.  Para quitar manchas persistentes, humedezca un paño suave que no deje pelusas con limpiador para lentes y frote la lente con cuidado. No rocíe ningún líquido directamente sobre la lente.  Advertencia: No utilice un limpiador para lentes que contenga gas inflamable. El alto calor generado por la lámpara del proyector puede causar un incendio.    #USX.PR1472 Como realizar mantenimiento de un proyector  Precaución:  No utilice limpiador de vidrios o cualquier material abrasivo para limpiar la lente y no la sujete a ningún impacto ya que la podría dañar. No utilice aire comprimido en lata ya que los gases pueden dejar residuos. No toque la lente con las manos descubiertas para evitar dejar huellas en la superficie de la lente o dañarla.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('141', 'DCD.T0000140', 'Como realizar mantenimiento de un proyector - Limpieza del exterior', 'técnico', 'Antes de limpiar el exterior del proyector, apáguelo y desconecte el cable de alimentación.  Para quitar polvo o suciedad, use un paño suave y seco que no deje pelusas.  Para quitar suciedad persistente, humedezca un paño con agua y con un poco de jabón suave. No rocíe líquido directamente sobre el proyector.  Precaución:  No utilice cera, alcohol, benceno, diluyente de pintura u otros productos químicos para limpiar el exterior del proyector. Estos productos pueden dañarlo. No utilice aire comprimido en lata ya que los gases pueden dejar residuos inflamables.    #USX.PR1472 Como realizar mantenimiento de un proyector', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('142', 'DCD.T0000141', 'Como realizar mantenimiento de un proyector - Limpieza del filtro y de las salidas de aire', 'técnico', 'El mantenimiento regular del filtro es importante para mantener el proyector en buen estado. Este proyector Epson fue diseñado con un filtro de aire de fácil acceso que se puede reemplazar por el usuario con el fin de proteger el producto y hacer sencilla la tarea de darle mantenimiento regular. La frecuencia de mantenimiento del filtro de aire puede variar según el entorno.    Si no se realiza un mantenimiento regular del producto, este proyector Epson le notificará que la temperatura interna ha alcanzado un nivel alto. No espere a recibir este aviso para darle mantenimiento al filtro de aire del proyector ya que la exposición a altas temperaturas por un periodo prolongado puede reducir la vida útil del proyector o de la lámpara.    Daños causados por la falta de mantenimiento al proyector o al filtro de aire pueden no estar cubiertos por la garantía limitada del proyector o de la lámpara    Fuente: https://files.support.epson.com/docid/cpd3/cpd39529/source/maintenance/concepts/maint_projector.html    #USX.PR1472 Como realizar mantenimiento de un proyector', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('144', 'DCD.T0000143', 'Como realizar purga de marcas de tiempo en los reloj control', 'técnico', '1) #USX.PR1365 iniciar sesion superadmin en reloj control  2) opcion sistema presiona ok  3) opcion datos presiona ok  4) opcion borrar reg y presiona ok  5) presiona ok, presiona ok, presiona esc, presiona esc    ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('145', 'DCD.T0000144', 'Como realizar recarga a número de teléfono Entel', 'técnico', 'Solicitar a #claudio la recarga del telefono.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('146', 'DCD.T0000145', 'cómo realizar respaldos en switch ', 'técnico', '1. Ingrese a l URL https://goreohiggins.unmsapp.com (Solicitar credenciales a #claudio)  2. en el dashboard seleccione el icono \"devices\" que está al lado izquierdo de la pantalla, cuarta posición.  3. selecciones un switch, click boton izquierdo del mouse.  4. en el dashboard presentado seleccione, en el menu lado latera izquierdo la opción backup.  5. luego seleccione el boton \"Create Backup\" que está en la parte lateral derecha superior.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('147', 'DCD.T0000146', 'Como realizar shrink al log de transacciones de una base de datos sql server', 'técnico', 'Shrink the transaction log    Use the following steps to truncate the transaction log file:    Note: You need the sysadmin fixed server role or the db_owner fixed database role to shrink the log.    Right-click the database and select Tasks -> Shrink -> Files.    Change the type to Log.    Under Shrink action, select Release unused space and click OK.  ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('148', 'DCD.T0000147', 'Como realizar speedtest desde un ubiquiti edgerouter', 'técnico', 'Para realizar un speedtest desde un ubiquiti edgerouter primero debe instalar speedtest client, para ver como hacerlo, puede seguir los pasos descritos en:   #USX.PR1428 Como habilitar speedtest en un ubiquiti routeredge    Una vez instalado el programa:  1) Ingresar a la consola del gateway   2) Ejecuta el comando: date  3) Ejecuta el comando: speedtest-cli --no-pre-allocate  4) Copia el el resultado de los comandos ejecutados en los pasos 2 y 3 y cierra la ventana.   5) Si vienes de una tarea, pega el texto e un comentario de esa tarea.  ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('149', 'DCD.T0000148', 'Como realizar un RESET al transmisor o receptor de video', 'técnico', 'En ocasiones podemos encontrar el error Tx´s input is un-supported (#USX.EC22086), esto puede ocurrir por algún tipo de anomalía en la transmisión de la señal de video entre el TX y el RX, cuando eso ocurra, necesitará realizar un RESET al dispositivo TX, pero, quizás también lo requerirá hacer en un dispositivo RX.    Con el dispositivo energizado, presione el botón RESET por alrededor de 10 segundos, y observe que las luces de testigo de señal se apagan y se vuelven a encender, tenga en consideración que si esta acción decide realizarla de manera preventiva, debe contar con unos 20 segundos sin señal de video.  ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('150', 'DCD.T0000149', 'Como realizar un respaldo a Avaya IP Office Manager', 'técnico', 'Este procedimiento muestra como generar un respaldo con toda la configuración de la plataforma de AVAYA IP Office Manager en GOREOHIGGINS.  En el documento que se adjunta a este procedimiento se hace referencia a:  #USX.PR1400 Como acceder a Avaya IP Office Manager en GOREOHIGGINS y por lo tanto necesitará conocer la contraseña de acceso a la administración de esa plataforma.  PC-SOPORTE, D:\\Backup\\Avaya IP Office', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('151', 'DCD.T0000150', 'Como realizar una limpieza de datos de sistema en un Iphone', 'técnico', 'https://viralitrix.com/que-son-los-datos-del-sistema-en-iphone-y-como-borrarlos-2021/  ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('152', 'DCD.T0000151', 'como recuperar contraseña de usuarios Microsoft Windows ', 'técnico', 'Este proceso se aplico a servidor sise #USX.S1389 Servidor Virtual Windows Server (sise.dellibertador.cl)    Se debe usar el iso de Linux HBCD_PE_x64.iso  se botea y luego se usa la herramienta password para el cambio de la contraseña', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('153', 'DCD.T0000152', 'como recuperar contraseña para Adobe', 'técnico', '', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('154', 'DCD.T0000153', 'Como reestablecer valores de fabrica en cerradura inteligente DAHUA', 'técnico', 'Este procedimiento aplica a #AK7902073 y #AK7902074    Retire los tres tornillos que aseguran la parte interna de la chapa, la que va hacia dentro.  En el reverso encontrará un botón metálico (esta etiquetado como DEFAULT en la placa electronica #USX.T628898 IMG RESET-CERRADURA), presiónelo unos segundos. Esta acción borrará todo de en la chapa, incluyendo las contraseñas de desbloqueo, tarjetas o fichas mifare y pareos bluetooth.  Para establecer una nueva contraseña de administrador, usted deberá:  1) Retirar la tapa plástica que cubre las baterías.  2) Presionar el botón de enrolamiento  3) Digitar 1 2 3 4 5 6 # en el panel de acceso.  4) Ingrese la nueva clave de administrador y presione la tecla # (haga esto dos veces)    Más detalles puede encontrar en:  #USX.PR1487 Manual de Usuario de Cerradura Inteligente DAHUA  #USX.PR1486 Manual de Instalación de Cerradura Inteligente DAHUA', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('155', 'DCD.T0000154', 'Como re-iniciar el servicio ExtractorTime', 'técnico', '1) Inicia una sesión remota RDP al servidor GORE-DAF-SRV02 (10.6.1.42)  2) Abre CMD en modo Administrador  3) Ejecuta NET STOP ExtractorService  4) Ejecuta NET START ExtractorService  FIN    Nota: En el servidor existe una tarea programada que realiza un reinicio, pero, no sirve para aplicar los cambios de configuración, esa tarea se ejecuta todos los días a las 0:14 horas.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('156', 'DCD.T0000155', 'Como reiniciar reloj control de goreohiggins', 'técnico', 'Modo remoto  1) Conéctate al reloj control via web usando una de las dos URL:       rcw1.goreohiggins.cl       rcw2.goreohiggins.cl    2) Inicia sesión con la cuenta de administrador    3) En el panel izquierdo, grupo \"Terminal\", Clic en la opción \"Reboot\"    4) Espere 30 segundos, y vuelva a conectarse al la URL del reloj control, para asegurar que se ha reiniciado.    Si no logra conectarse remotamente, deberá:  1) Conseguir la llave del reloj  2) Abrir la cajuela, desenchufar y luego enchufar. ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('157', 'DCD.T0000156', 'Como reiniciar un dispositivo POE remotamente desde un switch UISP', 'técnico', '1.  Se debe ingresar a la administración UISP -->https://goreohiggins.unmsapp.com/ (solicitar credenciales a #claudio de ser necesario)  2.  Seleccionar el icono Devices (es cuarto icono lado derecho).  3.  Seleccionar Switch USR-POE-DAF-01 (#AK7902176)  4.  En el dashboard debe desplazarse hacia abajo hasta llegar a los puertos del switch.  5.  Ubicar la puerta 8 del switch.  6.  Seleccionar en la última columna con el mouse boton izquierdo (aparecen 3 puntos verticalmente)  7.  Haga click en la opción del menú que indica \"Reset port link and PoE power\", esto desconectará y conectará el AP UAP-Outdoor:49b1 (#AK7902176)  8.  Para validar lo realizado en el punto 7, desplazarse hacia abajo con el mouse, hasta la zona de \"Events\"  9. De acuerdo al punto 8 debe revisar los siguientes mensajes de la acción realizada en el punto 7  UAP-Outdoor:49b1 (port8) has been connected.  UAP-Outdoor:49b1 (port8) has been disconnected.  10. Con las acciones realizadas se homologa una des-conexión física de acuerdo al procedimiento #USX.PR1362 Como resolver desconexión de UAP-Outdoor:49b1', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('158', 'DCD.T0000157', 'Cómo remover usuarios de listas de distribución en Exchange', 'técnico', '1. Ingresar a la plataforma web  2. En el menú centro de administración, hacer click en Exchange  3. En el menú de lado izquierdo seleccionar destinatarios  4. En la ventana del lado derecho buscar el grupo al cual pertenece el usuario  5. Una vez identificado el grupo hacer doble click  6. Se levantara una ventana, en el menú seleccionar pertenencia  7. Identificar el usuario y seleccionar   8. Arriba del recuadro hay unos botones de (+) y (-), para el caso pinche (-)  9. Luego pinche el botón guardar', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('159', 'DCD.T0000158', 'Cómo reportar problemas de enlace a movistar (degradación-intermitencia-caída internet)', 'técnico', 'Esto se hace a través de la plataforma   llama al <strong>800214242</strong>   digita RUT del GORE <strong>722404009</strong>  marca opción <strong>2</strong>  marca opción <strong>1</strong>  luego marca opción <strong>1</strong>  espera para transferir con un ejecutivo <strong>...</strong>  entregar el número del servicio internet <strong>VPF2088262</strong>   deberás entregar tu nombre, número de teléfono de contacto y correo electrónico    6006000843 soporte directo  anotar el número de caso que entregará el ejecutivo    Llamar a #paula.baltierra y entregar el número del caso  Si no contesta, llamar a #jorge.donoso y entregar el número de caso    Código de Servicio: VPF2088262 (Principal)  Nacional: 300 Mbps (simétrico)   Internacional: 60 Mbps (simétrico)    Código de Servicio: VPF2088263 (Respaldo)  Nacional: 95 Mbps (simétrico)   Internacional: 20 Mbps (simétrico)', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('160', 'DCD.T0000159', 'Cómo reportar una caida del sitio web www.goreohiggins.cl', 'técnico', 'procedimiento que aplicaría todo lo que se refiere a cpanel.    1. enviar un correo a soporte.empresas@tie.cl y copiar a rodrigo.Benavides@isc.cl  2. contactar a Rodrigo Benavides rodrigo.Benavides@isc.cl , 9 9540 1398 en caso de necesitar una respuesta mas rápida  ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('161', 'DCD.T0000160', 'Como resolver conflicto de licencia Office', 'técnico', 'Cuando se presenta un problema como el descrito en #USX.EC22078, usted debería proceder como sigue:  1) Instalar Office 365 en el equipo.  2) Abrir cualquier aplicativo e irse directamente a cuenta y hacer clic activar licencia ingresando las credenciales del funcionario.  3) Cerrar aplicativo  4) Volver a abrir alguna aplicación Office 365 y verificar que quede activada con la cuenta.   ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('162', 'DCD.T0000161', 'Como resolver desconexión de UAP-Outdoor:49b1', 'técnico', 'Switch donde está conectado #AK7902176 el AP Exterior del edificio CORE #AK7902689    1. Se debe solicitar las llaves a la guardia para ingresar a la sala de comunicaciones  2. Identificar la conexión etiquetada en el switch #AK7902176 puerta 8  3. Desconectar cable.  4. Volver a conectar cable.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('163', 'DCD.T0000162', 'Como resolver mensaje Value Key is missing ', 'técnico', 'Código de evento #USX.EC22068  1. Ingresar a la plataforma UNMS https://goreohiggins.unmsapp.com/ (las credenciales solicitarlas a Claudio Lillo | Oscar Leiva)  2. Una vez ingresado ir a la opción  Settings  > Credentials Vault section  3. Baje el archivo con la key del item propiedades de este procedimiento  4. Click en botón unload the key,  5. Un vez subido el archivo la alerta se corrije.    Nota: ver archivo \"credentials vault\" en item documento', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('164', 'DCD.T0000163', 'Como respaldar buzón de correo de Microsoft 365 de una cuenta de usuario desvinculado (Respaldo a PST)', 'técnico', 'Este procedimiento describe los pasos para dar de baja una cuenta de correo en Microsoft 365 respaldando previamente los correos de una cuenta en un archivo PST. Se aplica a las cuentas inactivas por mas de 90 días que se encuentren bloqueadas y cuyo titular ya no pertenece a la organización. Esta acción permite liberar licencias Microsoft.    1) Cambie la contraseña de la cuenta a dar de baja.  2) Configure un cliente de correo outlook en PC-SOPORTE con la cuenta a dar de baja.  3) Crea un archivo PST con el nombre de la cuenta a dar de baja, por ejemplo: nombre.apellido@goreohiggins.cl.pst (ver #USX.PR1258 Como agregar archivos \"pst\" al cliente de correo Outlook)  4) Mueve al PST, todos los mensajes de correo de la bandeja de entrada, elementos enviados y carpetas que el titular haya creado.  5) Una vez finalizado el proceso, desconecta el archivo PST del cliente de correo Outlook y muévelo a la carpeta de respaldo de archivos PST (ver #USX.PR1257 Ruta de Respaldos de Archivos de Correos de PST en servidores)  6) Finaliza la tarea informando la ruta en la que quedó el PST y el nombre del archivo.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('165', 'DCD.T0000164', 'Como responder al requerimiento de instalar Office cuando el usuario no tiene licencia asignada', 'técnico', 'Cuando un  usuario manifiesta tener problemas de licencia en programa de OFFICE (EXCEL, WORD, POWER POINT) primero debe validar que dicho usuario cuenta con licencia asignada para poder instalar estos programas en el PC.  Si existen licencias disponibles, debe solicitar la aprobación de #Carlos.Carrasco o quién el defina para .. ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('166', 'DCD.T0000165', 'Como restablecer un switch ubiquiti a partir de un respaldo', 'técnico', 'descarga firmaware reciente v1.9 lite  https://www.ui.com/download/edgemax/edgeswitch/default/edgeswitch-firmware-v180    configura tu interfaz de red como  ip 192.168.1.17  mask 255.255.255.0  gw 192.168.1.2      conectate a 192.168.1.2    inicia sesion con ubnt ubnt  ve a system -> Firmware -> Configuration and Upgrade  Haz clic en el icono de descarga de la linea Backup  Elige un archivo y selecciona el archivo que bajaste, espera a qu la transferencia se complete  luego en la linea NextActive, selecciona la versión más reciente y que corresponde al archivo que subiste  luego ha clic en submit  en seguida apaga el switch, espera 30 segundos y vuelve a encender el switch  debes esperar unos minutos hasta que veas que parpadean las luces del puerto donde tienes conectado el cable de red a tu equipo.    conectate a http://192.168.1.2  credenciales ubnt ubnt  cambia a la contraseña: G0r@.2020.pass    haz clic en unms  clic en add to unms cloud  username:   password    Confirmar ADD Device to UNMS    una vez vuelvas a la pagina de administracion del switch, el sistema intentará conectarse a internet para registarse en UNMS pero no podrá.  desconecta tu equipo y conecta el switch a la red    desde el administrador UNMS podrás ver el equipo conectado y desde allí podrás recuperar un respaldo.  https://goreohiggins.unmsapp.com/nms/login  local account  admintechgoreohigginscl  Ato.2020!    Para restaurar, ve al switch  opcion Backup  subir un backup de otro equipo igual  y luego, hacer clic en restaurar el archivo de respaldo.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('167', 'DCD.T0000166', 'Como restablecer y configurar anexo en teléfonos Avaya J129 ', 'técnico', '#USX.T611276   Procedimiento para restablecer teléfonos J129.    1 - Iniciar el teléfono conectándolo a cable de red.  2 - Esperar que inicie cargando todas las configuraciones.  3 - Una vez iniciado ingresar código CRAFT: 27238  4 - Presionar tecla ADMIN y elegir opción \"RESET DEFAULT\"  5 - Esperar que cargue el teléfono ya que se reinicia.  6 - Una vez de nuevo el teléfono iniciado presionar:  LOGIN (en esta opción ingresar ANEXO)  PASSWORD (1243)  7 -Se debe esperar que autentifique las credenciales de usuario (login y pass)  8- Teléfono reproduce sonido validando credenciales.  9 - Teléfono debería después de paso 8 quedar operativo.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('168', 'DCD.T0000167', 'Cómo restaurar a valores de fábrica un teléfono Avaya 9608', 'técnico', '1. Rebootear el telefono.  2. Presione el botón * para programar cuando se le indique    cuando el teléfono que se está iniciando.  3. Presione mute, luego escriba 27238 #  4. Aparecerá un menú, desplácese hacia abajo hasta Borrar y presione Iniciar.  5. La pantalla mostrará \"Presione Borrar nuevamente para confirmar\".  6. La pantalla mostrará \"Borrando valores\" y se reiniciará. El teléfono se reiniciará con los valores predeterminados de fábrica.  ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('169', 'DCD.T0000168', 'Como revisar el tipo de licencia de TeamViewer', 'técnico', '1. Se ejecuta la aplicación teamviewer  2. Se inicia sesión con la cuenta de soporte@goreohiggins.cl (solicitará autorización, se envía correo a la cuenta)  3. Ir a la pestaña \"ayuda\" del menú  4. Seleccionar \"Acerca de TeamViewer\"  5. Mostrará el cuadro con la información.  ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('170', 'DCD.T0000169', 'Como revisar proceso ExtractorTime de INGSOFT', 'técnico', 'El diagrama de arquitectura de ExtractorTime se encuentra en #USX.PR1222 Proceso Extractor Time    <b>Alternativa 1</b>  1. Ingresar por RDP al Servidor  2. Abrir el explorador de archivos  3. Ir a la siguiente ruta C:\\Program Files\\Extractor de Tiempo\\Log  4 Abrir el archivo del día credo, tiene la siguiente nomenclatura Log_DD-MM-AAAA  5 Verificar que los registros hayan iniciado correctamente debe esta la siguiente setencia \"Se ha completado el ciclo de extraccion\"    <b>Alternativa 2</b>  <a href=\"/ns/g6o6s/apps/1316831/extractor-time-status.asp\" target=\"_blank\">Log Extractor Time</a>', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('171', 'DCD.T0000170', 'Como revisar sitio http://inf.goreohiggins.cl/gpc/index.php', 'técnico', 'este sitio se encuentra en el servidor linux (#tecnotec.goreohiggins.cl)del host vm207 máquina vmware \"GORE-2017-Tecnotec-APPWeb  \", validar que esté encendida la máquina  Depto. de Recursos Físicos y Logistica  División Administración y Finanzas  Gobierno Regional O\'Higgins    #USX.T611216', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('172', 'DCD.T0000171', 'Como revocar certificado OPEN VPN', 'técnico', ' 1. Ingresar a la consola del gateway   2. Ejecutar comando sudo su   3. Ingresar a la siguiente ruta cd /usr/lib/ssl/misc   4. Mover las archivos del certificado desde la ruta /config/auth ej. mv /config/auth/carlos.carrasco.* /usr/lib/ssl/misc   5. Ejecutar la siguiente linea de comando: ./CA.pl -revoke carlos.carrasco.pem    6. Aparecerá lo siguiente párrafo una vez ingresada la clave gore:     Use of uninitialized value $reason in concatenation (.) or string at ./CA.pl line 190.   ====   openssl ca  -revoke \"carlos.carrasco.pem\"   Using configuration from /usr/lib/ssl/openssl.cnf   Enter pass phrase for ./demoCA/private/cakey.pem:   7. Luego aparecerá que el certificado está revocado,    Revoking Certificate 1007.   Data Base Updated   ==> 0   ====           7. Los archivos se deben mover a una carpeta que se creo llamada \"revoke\" ej. mv carlos.carrasco.* revoke/', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('173', 'DCD.T0000172', 'Como saber el limite de tamaño de un mensaje para un buzón de correo Exchange en Microsoft 365', 'técnico', 'Para conocer los límites de tamaño de mensaje para un buzón de correo, realice una de las siguientes acciones:    En el EAC, vaya a Destinatarios > Buzones de correo.    En la lista de buzones de usuario, haga clic en el buzón para el que desea comprobar los límites de tamaño del mensaje y, a continuación, haga clic en el icono Editar edición.    En la página de propiedades de buzones, haga clic en Características de buzón de correo.    En Restricciones en el tamaño de mensajes, haga clic en Ver detalles para comprobar los límites de tamaño de mensajes para el buzón.    O bien    Ejecute el siguiente comando en el Shell.  Get-Mailbox <identity> | fl MaxSendSize,MaxReceiveSize    Fuente: <a href=\'https://docs.microsoft.com/es-es/exchange/configure-message-size-limits-for-a-mailbox-exchange-2013-help\' target=\'_blank\'>Configurar límites de tamaño de mensaje para un buzón de correo</a>', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('174', 'DCD.T0000173', 'Como saber si tiene saldo en número de teléfono ENTEL', 'técnico', 'Para consultar si tiene saldo en un número Entel puede hacerlo de las siguientes formas:  1) Desde el teléfono debe marcar *103# (Tendrá un costo de 100 pesos por consulta)  2) Desde el teléfono intente enviar un SMS a otro número (el suyo), espere a recibir el mensaje un mensaje indicando que no pudo ser enviado por falta de saldo.    En caso que el número sea el +56952294443 y se encuentre sin saldo, por favor, genere una tarea a partir de la siguiente tarea recurrente:  #USX.RT1920 Realizar recarga Entel para número de teléfono +56952294443', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('175', 'DCD.T0000174', 'Como sacar el listado de numeros de telefonos con opcion de llamadas llamado \"Rutas de llamadas entrantes\"', 'técnico', '1. vaya a la consola de avaya con usuario y password  2. en el menu instancias, sellecione GOREOHIGGINS  3. selecciones la opción de \"Rutas de llamadas entrantes  4. traspase la información a una planilla de calculo\", esto se debe hacer en forma manual, el formato esta en #Usx.F3104', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('176', 'DCD.T0000175', 'Como sincronizar carpeta en Outlook 2013 con Exchange 365', 'técnico', 'Debido a la distancia de actualizaciones entre el cliente de correo outlook y exchange 365, se pueden experimentar dificultades para interoperar entre esta aplicacion cliente y el servidor de correo en la nube de microsoft.  Uno de los casos que suele aparecer es el de la no sincronizacion de carpetas outlook. Para ello, intente realizar los pasos que describen tras el siguiente enlace:  <a href=‘https://answers.microsoft.com/en-us/outlook_com/forum/all/office-365-email-folders-not-synchronized-to-my/79392dcf-861e-4ada-b9c5-d608f7d19295’ tarjet=‘_blank’> Office 365 email folders not synchronized to my Outlook 2013 desktop app</a>', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('177', 'DCD.T0000176', 'Cómo solicitar requerimientos y/o soporte al área de informática', 'técnico', '', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('178', 'DCD.T0000177', 'cómo solucionar cuando el reloj control se queda congelado', 'técnico', 'evento declarado #USX.EC22097  1. Se debe abrir el chasis del reloj (solicitar llaves a Andrea de RRHH)  2. luego desconectar la fuente de alimentación por 10 seg.  3. conectar alimentación  4. validar formato de fecha #USX.PR1326', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('179', 'DCD.T0000178', 'como solucionar error failure: file sustem chack of the root filesystem failed ', 'técnico', 'ejecute el siguiente comando:  fsck /dev/sda2', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('180', 'DCD.T0000179', 'Como usar y completar formulario registro de limpieza y desinfección', 'técnico', 'Descargue e imprima el formulario asociado en este procedimiento para cada integrante del equipo.  Haga entrega del formulario a cada uno e instruya que sea completado a medida que realice la labor de limpieza y desinfección de su puesto de trabajo.  Este formulario debe ser entregado al mes siguiente cuando vaya a recoger el kit sanitario del nuevo mes.    #Usx.F3067 Formulario de Registro y Control Mensual de Limpieza y Desinfección del punto de trabajo personal    Este procedimiento es implementado a partir de Noviembre del 2021, y cuyos correos donde se explica su origen puede encontrar en la tarea #USX.T622538 Implementar registro de control y limpieza de puesto de trabajo por funcionario  ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('181', 'DCD.T0000180', 'Como ver cuantas licencias tengo en Avaya IP Office Manager GoreOhiggins', 'técnico', '1. Ingrear a Avaya IP Office Manager con usuario y password  2. En menú GoreOhiggins seleccionar LIcencias  3. En el cuadro lateral derecho aparece la opcion de licencia  4. en el item Avaya IP endpoints aparace la cantidad para el caso 132 son las licencias para crear anexos.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('182', 'DCD.T0000181', 'Como verificar si DHCP Server se encuentra activo en el servidor de GOREOHIGGINS', 'técnico', 'Primero debes conocer el servidor DCHP en tu organización. IP: #10.6.2.17  Inicia sesión en el servidor  Abre una consola MSDOS como Administrador  Ejecuta el comando dhcp-status      Si el servicio está activo verás el texto \"El proceso asociado al servicio DHCP Server se encuentra activo.     En caso que no se encuentre activo verás el texto \"No se encuentra el proceso asociado al servicio DHCP Server\"', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('183', 'DCD.T0000182', 'Compartir un calendario de Outlook con otros usuarios', 'técnico', 'Compartir un calendario de outlook debe realizarse en el mismo equipo del usuario, por lo que debe coordinarse con el para hacerlo en su puesto de trabajo, o tomar control remoto de su computador.    Para ver este procedimiento, vaya al sitio de Microsoft y siga los pasos descritos allí.  <a href=\'https://support.microsoft.com/es-es/office/compartir-un-calendario-de-outlook-con-otros-usuarios-353ed2c1-3ec5-449d-8c73-6931a0adab88\' target=\'_blank\'>Compartir un calendario de Outlook con otros usuarios</a>  ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('184', 'DCD.T0000183', 'Conexión Management Studio de IngSoft', 'técnico', 'La conexión es a través del puerto 51618    #USX.T611321  #USX.T611299  #USX.S1369', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('185', 'DCD.T0000184', 'Configuración de cliente TeamViewer para conectarse sin ingresar credenciales', 'técnico', 'Para conectarse al PC-SOPORTE (#AK7902261)que tiene configurado Teamviewer en forma remota se debe realizar lo siguiente para usar la cuenta de #soporte  1. Se debe instalar el TeamViewer   2. Se debe configurar la cuenta de inicio de sesión ingresando la cuenta de soporte@goreohiggins.cl y su password', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('186', 'DCD.T0000185', 'Configurar cuenta office365 de goreohiggins en un ANDROID', 'técnico', 'Dirección de correo electrónico: Ingresa la dirección de correo electrónico completa (por ejemplo, nombre.apellido@goreohiggins.cl).  Nombre de usuario: su nombre de usuario es su dirección de correo electrónico completa (por ejemplo, nombre.apellido@goreohiggins.cl).  Contraseña: la contraseña de su cuenta de correo electrónico.    Configuración del servidor de entrada:  Nombre del servidor IMAP4: outlook.office365.com  Puerto: 995  Cifrado: SSL    Configuración del servidor de salida:  Nombre del servidor SMTP: smtp.office365.com  Puerto: 587  Cifrado: TLS    Configuración de autenticación: si el programa permite establecer configuración avanzada, use la siguiente configuración.  Active la opción “El servidor saliente requiere autenticación”.  Active la opción de configuración que le permite utilizar el mismo nombre de usuario y la misma contraseña para enviar correo electrónico.  No active la configuración de Autenticación de contraseña segura.  ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('187', 'DCD.T0000186', 'Configurar en DHCP \"Intentos de deteccion de conflictos\"', 'técnico', '1. Ir a propiedades de IPv4  2. seleccionar pestaña de opciones avanzadas  3. en opción \"intento de deteccion de conflictos\" (default=0), aumentar a 2      https://devblogs.microsoft.com/scripting/weekend-scripter-dhcp-address-conflict-detection/  Start the Microsoft Management Console (MMC) DHCP snap-in (Start, Programs, Administrative Tools, DHCP).  Right-click the DHCP server and select Properties.  Select the Advanced tab.  By default, \"Conflict detection attempts\" is set to 0. Increase the value to 1 or 2, as the figure shows. ...  Click OK.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('188', 'DCD.T0000187', 'Configurar telefono móvil institucional GOREOHIGGINS', 'técnico', 'Este procedimiento consiste en habilitar un teléfono móvil institucional del GOREOHIGGINS, este procedimiento aplica tanto para los casos en que un funcionario nuevo se le asigna un equipo o bien uno funcionario se le asigna uno por reemplazo.  Para ambos casos, las acciones a realizar son las siguientes:  1) Instale el chip asignado de la institución.  2) Instale Microsoft Outlook y configurelo con la cuenta del usuario, usuario y contraseña. recuerda que debes solicitar una contraseña para bajar aplicaciones, dependiendo del tipo de telefono.   3) Cofigura el telefono para que los números de la libreta de contactos se guarden en la nube, en este caso, usando la libreta de Office365  3) En caso que se trate de un usuario con reemplazo de equipo, y el cambio sea de iphone a android, es posible que requiera o necesite que le copien los datos desde el antiguo, siendo este el caso, puedes seguir las instrucciones del procedimiento #USX.PR1202 Como copiar los datos de contacto desde un Iphone a un Android', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('189', 'DCD.T0000188', 'Configurar VPN Zerotier en estación de trabajo', 'técnico', 'Instrucciones habilitación ZEROTIER y prueba de acceso       1) Descargue e instale la versión más reciente de ZeroTier  https://www.zerotier.com/download  2) Únase a la red (Opción Join Network) ID 565799d8f61c4f38  o b15644912e1461ac  3) según sea el caso:      a) Si es usuario: Informe a soporte@gorehiggins.cl respondiendo este mismo correo indicando que se está a la espera de autorización del acceso.       b) Si es de Unidad Informática: Genere la tarea subordinada  \"Habilitar nodo zerotier\" por cada cliente zerotier que instaló.  4) Una vez recibida la confirmación de autorizado (no más de dos horas) intente la conexión Autorizada.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
