INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('193', 'DCD.T0000192', 'Creación de cuenta para nuevo funcionario', 'técnico', '1.Ingresar al servidor de dominio 10.6.10.12  2.Ir a inicio de Windows -> Herramientas Administrativas->Centro de administración  Active Directory  3.Ir a nuevo->usuario  4.Completar información requerida    Ver documento adjunto', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('194', 'DCD.T0000193', 'Creación de listas de distribución para correspondencia electronica de GoreOhiggins', 'técnico', '1) Registrar lista en catalogo indicando (nombre, dirección, descripción, fecha de inicio y fecha de término, responsable, miembros, Clasificación)  2) Crear lista de distribución agregando siempre a partes@goreohiggins.cl, opcionalmente, agregar a los solicitantes.  3) Crear carpeta en el buzón de correo de partes@goreohiggins.cl el nombre debe ser el código obtenido en el paso 1  4) En caso que se indique clasificación automática, debes crear regla en la cuenta partes@goreohiggins.cl de modo que cualquier mensaje sea movido directamente a la carpeta asociada a la lista de distribución.  5) En caso que la lista de distribución tenga fecha de término, crear tarea para la fecha de termino para dar deshabilitar la lista de distribución.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('195', 'DCD.T0000194', 'CREACION DE USUARIO EN SISTEMA CORRESPONDENCIA METHASYS', 'técnico', 'En documento legacy se encuentra procedimiento', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('196', 'DCD.T0000195', 'Cual es la relación de aspecto de una foto para el sistema PYR', 'técnico', '5 ancho x 6 alto = 0.8333', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('197', 'DCD.T0000196', 'Datos de configuración para dispositivos móviles con dominio tech.goreohiggins.cl', 'técnico', 'Mail Client Manual Settings  If you do not see an auto-configuration script for your client in the list above, you can manually configure your mail client using the settings below:    Secure SSL/TLS Settings (Recommended)  Username: nombredecuenta@tech.goreohiggins.cl  Password: Use the email account’s password.  Incoming Server: tech.goreohiggins.cl  IMAP Port: 993 POP3 Port: 995  Outgoing Server: tech.goreohiggins.cl  SMTP Port: 465  IMAP, POP3, and SMTP require authentication.    Non-SSL Settings (NOT Recommended).  Username: nombredecuenta@tech.goreohiggins.cl  Password: Use the email account’s password.  Incoming Server: mail.tech.goreohiggins.cl  IMAP Port: 143 POP3 Port: 110  Outgoing Server: mail.tech.goreohiggins.cl  SMTP Port: 587  IMAP, POP3, and SMTP require authentication.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('198', 'DCD.T0000197', 'Desactivar bandeja de entrada Prioritarios y Otros en Outlook', 'técnico', '<strong>Outlook 2016</strong>  Haga clic en la pestaña Ver.  Seleccione Mostrar Bandeja de entrada Prioritarios.  Se mostrarán las pestañas Prioritarios y Otros en la parte superior de su buzón    <strong>Outlook en la Web</strong>  En la parte superior de la página, seleccione Configuración Icono de configuración .  En el panel Configuración, desactive en botón de alternancia de Bandeja de entrada Prioritarios.    <strong>Outlook.com</strong>  En la parte superior de la página, seleccione Configuración Icono de configuración .  En la Configuración rápida, desactive la Bandeja de entrada Prioritarios    Fuente: <a href=\'https://support.microsoft.com/es-es/office/desactivar-la-bandeja-de-entrada-prioritarios-f714d94d-9e63-4217-9ccb-6cb2986aa1b2\' target=\'_Blank\'>Desactivar la Bandeja de entrada Prioritarios</a>', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('199', 'DCD.T0000198', 'Desbloquear usuario de Microsoft 365 ', 'técnico', 'Cambie la contraseña de la cuenta en Active Directory    Vaya a: https://security.microsoft.com/restrictedusers  Seleccione al usuario y haga clic en desbloquear  Luego haga clic en siguiente.  Pruebe que tenga acceso al outlook web  ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('200', 'DCD.T0000199', 'Desbloqueo de iPAD', 'técnico', '', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('201', 'DCD.T0000200', 'Desvinculación de Usuarios', 'técnico', 'Cuando se notifica a un colaborador de la desvinculación se debe seguir el siguiente procedimiento:  1. Jefatura notifica por correo a soporte@goreohigins.cl que el usuario no pertenece a la organización  2. La unidad de informática procede a deshabilitar la cuenta (no borrar)  3. Luego se coloca en descripción la fecha de desvinculación ej. Jonathan Polanco Jara - DESVINCULADO 16-10-2020  4. Después se mueve al usuario desvinculado a la unidad organizacional (OU) de Active Directory \"Desviculado\"', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
