INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('205', 'DCD.T0000204', 'extrator_time (programador de tarea)', 'técnico', 'Se programa nueva tarea de reinicio del servicio a las 00:05 horas  Alcance: Se crea cuenta de usuario de dominio extractor.time #extractor.time y se agrega al grupo de administrador local del servidor #USX.S1381 Servidor Virtual Windows Server (gore-daf-srv02.goreohiggins.cl)  Se prueba operación de tarea a las 09:50, ejecutándose correctamente.  El Programador de tareas finalizó correctamente la instancia \"{7fc388ec-f789-4f24-8568-53f2c9edd0d9}\" de la tarea \"\\extractor_time\" para el usuario \"GOREOHIGGINS\\extractor.time\".', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('206', 'DCD.T0000205', 'Guia de servicio y actualización de HP ALL IN ONE 24-XA009LA', 'técnico', 'Descargue el documento adjunto a este procedimiento.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('207', 'DCD.T0000206', 'Habilitacion Token USB #pablo.silva', 'técnico', '1) Ingresar a https://www.e-certchile.cl/ecert/site/edic/base/port/verificacion_ayuda.html#ayuda?tab=2  2) Pinchar en \"Manuales Firma Electrónica Avanzada\"  3) Descargar driver segun sistema al que se requiera instalar   4) Descomprimir archivo descargado e instalar la version x32 o x64 segun corresponda el sistema operativo  5) Instalar Driver con Token USB \"DESCONECTADO\"  6) Conectar Token USB una vez finalizada la instalacion de Driver  7) Al momento de contectar el Token USB solicitara aprobar la instalacion de un Certificado al cual debemos dar que Si  8) Configurar Microsoft Edge para que sitio web https://siaper.contraloria.cl/ sea ejecutado en \"Modo compatibilidad Internet Explorer\" siguiendo los pasos del siguiente enlance https://learn.microsoft.com/es-es/deployedge/edge-ie-mode-local-site-list  9) Una vez configurado, el navegador nos dira que la configuracion aplicada estara vigente durante 30 dias y pasado esos 30 dias se debe volver a realizar la configuracion.  10) Realizado ya todos estos pasos, estaremos listos para firmar cualquier documento en plataforma https://siaper.contraloria.cl/', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('208', 'DCD.T0000207', 'How to Install 32-bit Software on 64-bit Windows 10', 'técnico', 'Vea el enlace siguiente:  <a href=\'https://teckangaroo.com/install-32-bit-app-64-bit-windows-10/\' target=\'_balnk\'>How to Install 32-bit Software on 64 bit Windows 10</a>    O descargue el PDF asociado a este procedimiento.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('209', 'DCD.T0000208', 'Iniciar una sesión TeamViewer con la cuenta de soporte@goreohiggins.cl', 'técnico', 'En la ventana principal, haga clic en Iniciar Sesión (ubicada en el panel derecho) he ingrese la cuenta soporte@goreohiggins.cl con su contraseña (solicitar a #claudio)  Active la casilla de verificación \"Mantener la sesión iniciada\"', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('210', 'DCD.T0000209', 'Instalación de impresora de cheques Epson M253A', 'técnico', 'Buscamos en www.google.cl \"driver Epson M253\"  la idea es que sea la ultima version y nos descargar un ejecutable  Abrimos  Hacemos clic en siguiente, siguiente, siguiente   La impresora comenzara a hacer un ruido lo cual es normal   Siguiendo los pasos anteriores la impresora deberá estar instalada y funcionando correctamente', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('211', 'DCD.T0000210', 'Instalación de software PyR', 'técnico', 'Instala el software según las indicaciones del documento PDF incluido en este procedimiento.  No olvides instalar el parche de actualización.    ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
