INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('213', 'DCD.T0000212', 'INSTALACION DEL SISTEMA DE CONTABILIDAD ', 'técnico', 'Sistema #USX.S1367  Sistema en carpeta TI de equipo de pc-soporte #AK7902261  D:\\TI$\\SOFTWARES GORE\\CONTAB Servicio de Bienestar Sector Pubico (#USX.S1367)    1. Copiar las carpetas     contab17  contab18    en el disco C    2. Copiar en el escritorio el acceso directo  VPRO5 - Acceso directo    Nota: el caracter \"-\" del manual es más grande y esto implica que da error', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('214', 'DCD.T0000213', 'INSTALACIÓN ODBC SEGURIDAD', 'técnico', '      #USX.T610964', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('215', 'DCD.T0000214', 'Instalación y configuración de NUEVOS equipos Desktop/Notebook GORE.', 'técnico', 'En este procedimiento se describen los pasos a seguir cuando toca instalar un equipo Desktop / Notebook nuevo para algún funcionario/área en el GORE:    1 - Configuración de sistema operativo.  2 - Configuración de usuario Administrador (cuenta local). Usuario: Admin Pass: Gore2020   3 - Subir equipo a dominio #USX.PR1254  4 - Configuración de perfil de funcionario: es de importancia tener la contraseña del usuario a quien se le entregara el equipo para poder configurar su perfil). Ejemplo: jose.perez@goreohiggins.cl pass: Gore.2020  5 - Instalación de Office 365 (en caso de que no venga ya instalado en el equipo provisto) + (validar licencia si es que el funcionario la tiene).  6 - Instalación de software restante:  * VPN #USX.PR1253  * Google Chrome (y dejarlo por defecto en settings). Y dejar Office 365 + Outlook en favoritos.  * Microsoft TEAMS (y sacar la opción para que abra al iniciar windows).  * Zoom (y descargar complementos para Office y Chrome).  * Adobe Reader  * TeamViewer  * Anydesk  * Recursos compartidos (en caso de que se requieran).  * Software de gestión especifico (en caso de que se requiera): P&R #USX.PR1252 / Methasys #USX.PR1251 / Control de Inventario y Bodega #USX.PR1250  * CCleaner.  7 -  Dejar accesos directos de Word, Excel y Outlook en escritorio.  8 - Dejar el equipo con las redes Gorewifi y GoreV conectadas para que el funcionario no tenga que solicitar claves al utilizar equipo en dependencias.  9 - Instalación de UPDATES de Windows (esto es muy importante).  10 - Generación de activo fijo y etiquetado correspondiente.  11 - Envío de mail informando entrega formal a RRFF, funcionario que recibirá el equipo y jefatura.    Adicional:  Se debe brindar inducción a funcionario que reciba equipo mas que nada para demostrar que el mismo ya esta operativo, se conecta remoto a su equipo de escritorio y para que funcionario aprenda a conectarse vía VPN y sepa como acceder a Office 365 WEB en caso de algún día tener problemas con el Office 365 instalado en el equipo que recibe.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
