INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('233', 'DCD.T0000232', 'Methasys Mensaje de Advertencia de Seguridad', 'técnico', 'Para poder eliminar el mensaje de “Advertencia de Seguridad” que da Methasys al abrir el software:    1 - Seleccione «Comienzo«, Luego escribe»opciones de Internet“.  2- Abierto «opciones de Internet“.  3 - Selecciona el «Seguridad» pestaña.  4- Seleccione «Intranet local«, Luego seleccione»Sitios» botón.  5- Elegir la «Avanzado«Botón en el»Intranet local”Cuadro de diálogo que aparece.  6- Escriba la ubicación/ruta del archivo que produce la advertencia y presione «Agregar“.  7- Seleccione «Cerrar«>»Aceptar«>»Aceptar“.    Existe un tutorial con imágenes enviado a grupo ti@goreohiggins.cl', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
