INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('244', 'DCD.T0000243', 'Procedimiento de instalación y configuración de VPN (Virtual Private Network).', 'técnico', 'La VPN debe ser instalada en todos los equipos Notebook ya que es esencial para el trabajo remoto.  Usar el producto de software: #USX.SW1033 OpenVPN Client 2.4.6-I602    1) Descargue el producto de software OpenVPN Cliente desde el <a href=\'http://soporte.goreohiggins.cl:8171/software/openvpn/sw1033.zip\'><b>enlace</b></a> (usa tus credenciales de goreohiggins)  2) Instale el producto OpenVPN Cliente en la ruta estándar (C:\\Archivos de Programa)  3) Descargue el paquete de configuración VPN para el usuario desde el <a href=\'http://soporte.goreohiggins.cl:8171/software/vpn/indice.asp\' target=\'_blank\'><b>enlace</b></a> (usa tus credenciales de goreohiggins), busca el nombre del usuario y descarga el paquete.  4) Descomprime el paquete, y copia o mueve la carpeta Config a la ruta de instalacion de OpenVPN Cliente.  5) Realiza una prueba de conexión VPN con el computador conectado a una red WAN (desde internet) usando alguna red 3G, 4G o desde otro lugar con acceso a internet que no sea la red de GOREOHIGGINS. Realiza una prueba de conexión a un equipo dentro de GOREOHIGGINS, pueses usar el mismo computador de escriotrio del funcionario. si ves un error en el log de conexión pero, lograste conectar con un computador en la red LAN, ignora el mensaje.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('245', 'DCD.T0000244', 'Procedimiento Encendido Global Sala de Computación Goreohiggins', 'técnico', 'El Encendido comprende:  Sala de computación con sus 3 racks  Sala de computación DAF con 1 rack    El alcance del encendido es conectar el cable que alimenta al equipo y por boton físico    1. Se conectan 3 enchufes que estan detras de rack 3 #AK7902130  2. Se prende UPS (#AK7902905, #AK7902815 y #AK7902816)  3. Se prenden los servidores wmware  4. Se prenden los NAS  5. Se conectan cable de poder a los switchs, prenden automáticamente  6. Se conecta cable de poder a la Central telefonica y boton de encendido  7. Se conecta cable de poder NVR y boton encendido  8. Chequeo de servicios', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
