INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('250', 'DCD.T0000249', 'Proceso Extractor Time', 'técnico', 'El proceso está descrito en el documento adjunto.  Consiste en extraer los datos (server 10.6.1.42)de los dos reloj control y llevados a la base de datos pyr (server 10.6.1.41)  cada vez que el proceso se ejecuta, y de acuerdo a la configuración (hoy cada 15 minutos, entre 10 y 22:00, recolecta el mes) trae todas las marcas del mes en curso.   Debe tener en cuenta que, si alguien marca su salida después de la última recolección del último día del mes, esa marca nunca será cargada, porque al día siguiente el proceso considera las marcas del nuevo mes.    UPDATE!  Debido a que las horas con mayor número de marcas son 7, 8, 9, 16, 17, 18 y 19 se necesita que en esas horas no se ejecute el proceso de extractor de marcas (ExtractorService)  Para ello, se han creado tres archivos de configuración llamados configuration.am.xml, configuration.pm.xml y configuration.or.xml, se crearon tres archivos BAT llamados ExtractorServiceSchedule.am.bat, ExtractorServiceSchedule.pm.bat y ExtractorServiceSchedule.or.bat  Estos archivos realizan lo siguiente:  Detiene el servicio ExtratorService  Cambia reemplaza el archivo Configuration.xml por uno de los tres archivos de configuracion Configuration.am.xml o Configuration.pm.xml o Configuration.or.xml   Inicia el servicio ExtratorService    El archivo Configuration.am.xml tiene la hora desde 10:00 a 16:00  El archivo Configuration.pm.xml tiene la hora desde 20:00 a 23:50  El archivo Configuration.or.xml tiene la hora desde 10:00 a 22:00  ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
