INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('256', 'DCD.T0000255', 'Quitar y eliminar la licencia de Microsoft 365 de un antiguo empleado', 'técnico', 'Cuidado: si va a remover la licencia básica, antes deberá respaldar el buzón en un archivo PST.    https://docs.microsoft.com/es-es/microsoft-365/admin/add-users/remove-former-employee?view=o365-worldwide#remove-and-delete-the-microsoft-365-license-from-a-former-employee', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('257', 'DCD.T0000256', 'Reasignación de Licencia Office 365', 'técnico', 'Cuando un colaborador se retira o es desvinculado de la organización, se debe reasignar el uso de la licencia Office365.  La consideración que se debe tener es que al reasignar la licencia, los correos del usuario antiguo quedarán por 30 días y luego será eliminado.    Cuando un funcionario deja de pertenecer a la organización:  1) se bloquea la cuenta de correo. (por 30 días)  2) a los 30 días, se respalda su correo a pst (se baja y se guarda) Procedimiento #USX.PR1267  3) a los 30 días y con el pst guardado, se le quita la licencia  para cumplir con ese protocolo:  el punto 1, 2 y 3 pueden realizarse en ese orden inmediatamente después que el funcionario ya no está en la organización, con autorización de la contraparte  que es Carlos Carrasco -> Ricardo Gonzalez', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('258', 'DCD.T0000257', 'Renovar un dominio de GOREOHIGGINS en NIC.CL', 'técnico', '1) Obtiene la contraseña para carlos.carrasco@dellibertador.gob.cl en NIC.cl  2) Conéctate a NIC.cl a la siguiente dirección: https://clientes.nic.cl/registrar/logon.do  3) En la lista Mis Dominios, haz clic en el icono de carro de compras del dominio que está por vencer.  4) En el carro de compra, asegúrate de seleccionar como plazo 1 año y luego sigue los pasos para el pago.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('259', 'DCD.T0000258', 'Restablecer sistema operativo para DESKTOP y NOTEBOOK', 'técnico', '1) Solicitud va por soporte y debe incluir siempre el nombre del ultimo usuario que usó el equipo.    2) Restablecer sistema operativo consiste en retirar el disco duro, rotularlo y guardarlo en custodia, e instalar un disco nuevo SSD con el sistema operativo original, actualizado a Windows 10. Y debe quedar configurado y listo para su personalización (cuenta administrador, subido a dominio, productos básicos) Para ello debe usar las instruccioones indicadas en:     #USX.PR1249 Instalación y configuración de NUEVOS equipos Desktop/Notebook GORE.    3) El equipo será envuelto en FILM plástico, con un identificador de la última tarea en que se intervino el equipo y una etiqueta con el texto REBURBISHED y guardado en bodega de Informática', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('260', 'DCD.T0000259', 'Revisar fecha de caducidad de Certificado Token USB #AK7904819', 'técnico', 'Para revisar fecha de caducidad de certificado, debemos tener conectado el Token USB en el equipo con el driver instalado  Una vez finalizada la instalacion (procedimiento de instalacion #USX.PR1519)  1) Abrimos la aplicacion SafeNet Authentication Client   2) Pinchamos en el engranaje arriba a la derecha   3) Clic en dispositivos   4) Clic en certificados y nos apareceran los certificados instalados en el Token USB conectado con todos los detalles ', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('261', 'DCD.T0000260', 'Ruta de Respaldos de Archivos de Correos de pst en servidores', 'técnico', 'Los archivos de correo \"pst\" se encuentran en dos servidores que son:  1.- rcgua-data-01.goreohiggins.cl [10.6.2.16]        Carpeta K:\\PST       Carpeta K:\\RESPPST  2.- rcgua-data-02.goreohiggins.cl [10.6.2.18]       Carpeta E:\\RPST2    Se deben copiar en la carpeta local del usuario y agregarlo al cliente de correo según procedimiento #USX.PR1258', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('262', 'DCD.T0000261', 'Sistema Administrador de Seguridad. (Este solo para TI)', 'técnico', '', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('263', 'DCD.T0000262', 'Sitio para bajar driver de servidores Dell R720', 'técnico', 'http://delldriverdownload.info/poweredge-r720-os-independent-drivers/    #AK7902192 PowerEdge R720', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('264', 'DCD.T0000263', 'Solicitar Soporte de Telefonía a Movistar (Avaya)', 'técnico', '1. Llamar a Movistar al número 800214242  2. Ingresar RUT 72240400-9  3. seleccionar la opción 2  4. seleccionar la opción 2 (nuevamente)    Nota: Central Telefónica Avaya  Cabecera: 72 2205900    Procedimiento para seguimiento de casos #USX.PR1317', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('265', 'DCD.T0000264', 'Solicitud De Correo Electrónico Institucional', 'técnico', '1. Jefatura envía correo a unidad de informática soporte@goreohiggins.cl con los antecedentes de la cuenta a crear.  2. Unidad de Informática procede con la habilitación del correo una vez creada la cuenta en Active Directory (AD) según procedimiento #USX.PR1236  3. Se notifica de creación de cuenta a requirente.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('266', 'DCD.T0000265', 'Solicitud de creación de usuarios cuentas Windows', 'técnico', '1. Jefatura envía correo a unidad de informática soporte@goreohiggins.cl con los antecedentes de la cuenta a crear.  2. Unidad de Informática procede con la creación de cuenta en Active Directory (AD) en la OU de \"Users\"  3. Se notifica de creación de cuenta a requirente.', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('267', 'DCD.T0000266', 'Solicitud de nuevas licencias', 'técnico', 'Office, Windows', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
