INSERT INTO `procedimientos` (`id`, `id_procedimiento`, `titulo`, `tipo_procedimiento`, `cuerpo`, `archivo_pdf`, `usuario_creador`, `fecha_creacion`, `fecha_ultima_modificacion`, `es_activo`) VALUES ('270', 'DCD.T0000269', 'Validación de licencia de Windows vía telefónica. ', 'técnico', 'Abrir explorador de windows  Clic en Este equipo  Clic derecho en un espacio en blanco y luego pinchar en propiedades  Nos abrirá una pantalla con  las características del equipo  Hacemos clic en activar producto y ingresamos la licencia que viene con el equipo (si es win7 viene una pegatina en la parte superior o lateral del equipo)  Si al hacer la validación po ese medio nos lanza una ventana de error, debemos proseguir con la validación telefónica para eso debemos llamar al 800 330 600, nos contestara una operadora de Microsoft la cual nos ira guiando de manera muy didacta en el proceso de validación.    Una vez hecho todo los pasos al pie de la letra ya tendremos la licencia validada e instalada en el equipo win7', NULL, '24', '2026-01-26 15:06:00', '2026-01-26 15:06:00', '1');
